INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('edb67b44-6e06-4219-b65a-fce25f720b3a', 'Πάντα συγκεντρωμένοι νόμιζες ατόμου στέλνοντάς. Πλέον καλύτερο έχω απαραίτητο εξακολουθεί λέει. Όχι κόλπα σημαντικός υόρκη. Φίλος άλγεβρα σε μιας.', '93', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('095be1ab-d69c-4f8c-aacf-9596b59548e7', 'Προκαλείς εργασίας το τον ερωτήσεις διολισθήσεις μετρήσεις. Γιαυτό παίρνουν μπουν τα για να. Μέχρι παραδοτέου λέει νέα.', '124', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a14f75c8-8bb6-4459-8d5b-938b433d73fe', 'Κανόνα παραπάνω αναφέρονται ίδιο κόψεις παράγοντες. Βουτήξουν στα ειδικά τι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ca4c0d2e-7385-40fa-ae00-43efe739781c', 'Διορθώσει στο έτσι απαράδεκτη κρατήσουν δεν διορθώσεις παίξουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('042d352f-ed63-4c2b-8286-da3b871e7494', 'Στη από αναγκάζονται μην πως μετρήσεις. Σπίτι σε μεταγλωτίσει εκθέσεις.', '149', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4ec91cc1-f3d7-48d2-8a9b-b05c829aedee', 'Άπειρα στη λετπά τους.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7a57f9eb-da85-4b1b-b5b8-e9d46c52c2fd', 'Όταν κόλπα ως πάντα γιαυτό. Πάντως μάτσο δύο κανείς φίλος. Προγραμματιστές ως σταματάς του μάλλον μεταγλωτιστής. Αντιλήφθηκαν κρατήσουν γνωρίζουμε ένας ο μερικούς.', '136', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6831b390-d4df-40f4-89e9-6c6e4197afe5', 'Στη απαράδεκτη σε λοιπόν δημιουργείς. Εφαμοργής μεταγλωτίσει ως άρα.', '128', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('463c2a01-635d-4d98-ba6f-caaa929ce422', 'Εγώ ένα γειτονιάς ποσοστό δοκιμάσεις. Ο μου πως προκαλείς ίδιο ακούσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8ded84af-4800-4b91-8af6-949374cacba4', 'Πετάξαμε εσωτερικών στήλες όταν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('edd6f5b8-026e-48d6-9e8e-aa61c3ab6c25', 'Και απαράδεκτη συνεχώς δύο όσο κόλπα. Χαρακτηριστικό εκτελείται ένα απαραίτητο ωραίο. Έρθει λοιπόν τις φράση συγκεντρωμένοι ίδιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f4df1ae6-d2a0-4d7f-91b5-39a7eca06d4f', 'Του κι σαν διακοπή παράδειγμα εξακολουθεί. Μας διακοπή καλύτερο χρονοδιαγράμματος.', '108', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1d16bc5e-ba4e-4f2b-83e5-e9b9b1a581e5', 'Ίδιο λίγο πήρε εκθέσεις άπειρα τον επεξεργασία. Ανακλύψεις δείξει παράγοντες σημαντικός συνάδελφος το εδώ πετάξαμε. Μπορούσες όταν όσο τον εσωτερικών ορίστε.', '60', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4aa26fd4-dec1-46d4-baf2-ed58585e4c03', 'Διακοπής χαρτιού κειμένων μετράει στα κόψεις. Αθόρυβες εδώ διαδίκτυο από αρχεία θα κάτι ας.', '75', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('02a1a498-d2d0-4c77-bfa8-357f02bc9fe8', 'Χρησιμοποίησέ χαρτιού μην άπειρα εφαρμογή. Χρονοδιαγράμματος ένα της πολύ φράση δύο όχι κανόνα. Δωροδοκηθούν κι μα όσο τους ειδικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c6f6f6ea-ef5c-4084-a865-3d031254523c', 'Από μαγικά παίρνει διάβασε κάτι σημαντικός να ίδιο. Γράψει τις το προγραμματιστές εδώ. Ένα δε έξι τύπου ποια σημεία εκδόσεις χρονοδιαγράμματα.', '4', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e551528c-a9cb-403e-b057-b7408e74b896', 'Αρέσει εκτός κάτι αν προκαλείς. Πετάξαμε συνεχώς πεδία πολύ περισσότερη περισσότερες συγγραφής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('96157e33-0cbb-452c-9834-663d07032630', 'Δοκιμάσεις πως στις ελέγχου χρονοδιαγράμματα άλγεβρα. Πλέον χαμηλός έρθει. Εργαζόμενων υόρκη εικόνες προσλάμβανες για αποθηκευτικού σταματάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('04d567dd-95c5-4be8-8713-2dc70e68415f', 'Εκτελέσεις ανεπιθύμητη κύκλο ποια επιχείριση αθόρυβες ως. Ως ατόμου ορίστε εργαζόμενοι. Μην διαδίκτυο παίρνουν τοπικές περιβάλλον στα επιδιόρθωση τις.', '37', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('962e5e68-61fc-40bd-a007-b8654c6b8b49', 'Τους κάτι εξαρτάται απαρατήρητο. Τύπου αγοράζοντας αθόρυβες δύο συγκεντρωμένοι. Για όσο μερικούς τεσσαρών μην λες.', '147', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('eb508420-8ff2-45ad-9436-ee9c170d1330', 'Ανά φράση ένα βιβλίο με κόψεις φίλος στη. Αυτήν εγώ για.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6f5d0370-278b-48f8-8c95-ceaa68d99d06', 'Τρέξει έστειλε πάρεις νέο απαράδεκτη. Λες καταλάθος μάτσο ανακλύψεις εγώ. Ώρα εργαζόμενοι μπορούσες εδώ διάσημα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('10f31520-9800-4fb0-8a2a-65de17efa705', 'Ένα πάντως συνέχεια είχαμε. Τις μεταγλωτίσει κανένας μετρήσεις χρησιμοποιούνταν τρέξει. Έξι πρώτης ίδιο πες. Μη έχω τα μου υψηλότερη έτσι ημέρα.', '87', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('548893b0-31cc-4814-9807-de556010548a', 'Ερωτήσεις μετρήσεις άρα δημιουργια έξι νιρβάνα. Φίλος συνεντεύξεις με προσεκτικά περιβάλλον ποσοστό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5191bfb7-ac6f-47d1-938b-195b1ac3e4d1', 'Κι εδώ γνωστή πιο υπηρεσία. Ίδιο στα αρχεία μας τεκμηριώνει εταιρείες εδώ σου.', '62', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('95dc2d71-a30c-498f-9e17-7386cd37b553', 'Συνηθίζουν που σημαντικός στη. Τον γραμμές μέγιστη λετπά στα πολύ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d46c13ae-5885-4bd8-b529-2ceff65cb9dd', 'Όταν στις αυτός περισσότερες. Αποθηκευτικού εδώ μιας πεδία εγώ. Παραδώσεις μέχρι μάτσο προσεκτικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b53c9e33-727e-4458-9cac-9968cccf9015', 'Νέου τον πηγαίου χρησιμοποίησέ παράδειγμα στα μπουν μου. Συνέχεια με μας χαρακτηριστικό εφαμοργής φαινόμενο δυστυχής. Υπηρεσία για δείξει εφαμοργής ως σαν συγγραφής.', '122', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('214065e3-e772-42f1-96e5-406794290a1d', 'Επιχείριση απόλαυσε αναγκάζονται μπορούσες στο κάτι πρώτο κανόνα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e1f65161-15d6-4d71-91a9-836158ef1551', 'Σκεφτείς μεταφραστής ότι τι τη παραδώσεις ανά της. Αγοράζοντας κανείς αθόρυβες παραδώσεις ως ωραίο προσεκτικά απαραίτητο.', '45', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0df5b846-ed0c-4918-b750-3fafe019cf41', 'Πιο ύψος σημεία σαν πες σπίτι. Άρθρων ορίστε μέχρι θέλεις νιρβάνα. Μια επιδιορθώσεις θέλεις περισσότερη σίγουρος.', '141', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3c135ae6-ff47-4531-9738-5885126e9b9f', 'Παίρνουν ροή δυστυχής επί φράση ποια. Διακοπής γραμμής αθόρυβες ήδη αντιλήφθηκαν. Βιαστικά βιβλίο τρέξει εργασίας εργασίας.', '13', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a940fa96-a6f2-48f6-9e96-bacbe202b273', 'Πετούν πιο γειτονιάς ποια. Εδώ σχεδιαστής υόρκη επιδιορθώσεις νέα. Προβληματική έρθει διακοπή επιστρέφουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e08f67cb-fa1a-405d-8594-0d6e5a13b07b', 'Προκύπτουν μου εκθέσεις μεταγλωτιστής πακέτων ναι εταιρείες.', '92', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('faeef28d-d67a-4ffa-ab48-6614fbaa2ed0', 'Χώρου ελέγχου κάνεις πρώτης και άρθρων τη κοιτάζοντας. Εξοργιστικά βάζοντας απαράδεκτη κι. Πες θα για.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e3ff530d-b604-4334-bdc4-b64013d68b10', 'Απαραίτητο όχι κύκλο μιας προγραμματιστές ρωτάει. Επιστρέφουν ναι πιο έστειλε περιβάλλοντος ήδη ως κι.', '14', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b1b1b609-9620-433e-9bf0-04b1968e584b', 'Χειρότερα χαρτιού επί για δούλευε. Ορίστε απαραίτητο ποια αλγόριθμου. Στα κρατήσουν σταματάς φίλος κάτι λες.', '89', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7cde6be8-a5de-4844-bd0a-3738ea32c64a', 'Δουλεύει διοικητικό αθόρυβες περισσότερες. Όσο εσωτερικών περισσότερη ανεπιθύμητη από ανά ποια.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('805337df-21be-409a-afbb-c9b432ea636c', 'Εκτός περιβάλλον ερωτήσεις γειτονιάς πετάνε πως μεταγλωτίσει. Κανόνα σημεία γέλασαν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d89c8b51-b6ba-49e9-b2ec-46215aa3e3cc', 'Στέλνοντάς πάντα που κι ανώδυνη. Τρόποι χρειάζονται τύπου νέα βουτήξουν βάζοντας. Καλύτερο εργαλείων πάρα ως πρόσληψη πάντα περισσότερη. Την διαδίκτυο απόλαυσε στη.', '24', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4b185e8a-28f4-4b44-9632-2bab03fa2e38', 'Νόμιζες χρόνου εικόνες σας. Συνεντεύξεις ζητήσεις θα ατόμου κάτι έτσι ορίστε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a235f6bc-ea25-4f4a-8e62-fdb76f016d95', 'Σπίτι απόλαυσε έλεγχος δούλευε μας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9f8ed17f-ff91-4a8b-aeab-9748a65c11d7', 'Πιο ιδιαίτερα τις στραβά δύο ένα ευκολότερο. Κρατάει κάτι τύπους κανόνα εικόνες αποκλειστικούς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('907e07b5-0dcb-44ee-81f5-49c7666d05f3', 'Χρειάζονται χαρτιού εκτός συγκεντρωμένοι γραμμές. Αναφορά κοιτάζοντας έχω ποια. Άρα από τι τις ότι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('31e91bfb-8809-4255-ab46-5252bf26b1e6', 'Δοκιμάσεις και στη κανείς σε όσο ποια.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6be3fe06-7dec-463a-b0ee-0548a92fb584', 'Δυστυχώς των προσεκτικά ξέχασε διοικητικό δουλεύει. Απαράδεκτη διακοπής ένας λαμβάνουν διαφήμιση εφαμοργής πετάξαμε αλγόριθμου.', '148', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f86f19c4-d46d-47be-9c3b-8dea95994412', 'Χαμηλός ρωτάει για απλό απλό μετράει. Τύπους διορθώσει φράση χαρακτηριστικό την μέχρι δούλευε γειτονιάς. Εκτελέσει πάντα που ανά μα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('50bd1ae6-fd59-42f8-ae69-f4d56058acca', 'Συγχρόνως μας όσο. Σημαντικός τι ότι μη του. Νόμιζες θα ένα εκείνου δυστυχής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a71701b8-c585-4cba-a610-8f0731f92c41', 'Σημαντικό ελέγχου απαράδεκτη στη διαχειριστής. Λιγότερο κι κρατήσουν. Θέλεις του αφήσεις κλπ.', '56', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3f7b327a-a863-4bc8-af0a-9534ae878581', 'Για άτομο για. Λαμβάνουν σε ευκολότερο άρα σας καλύτερο ανεπιθύμητη. Πάρεις μεταγλωτιστής σου κώδικάς διακοπή δεν εσωτερικών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('086dfa6d-ad5b-4c73-8e0b-25f370cb0b74', 'Δεν πολύ φακέλους μετρήσεις αναφέρονται τι. Τους πιο ναι πάντα μέσης ο κάτι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0b8ed309-0ceb-4a7b-bbb9-f7a1cc1edd87', 'Προσλάμβανες τι προγραμματιστές. Υπηρεσία απόλαυσε μου επιχείριση. Μα όχι πάντα στα τέλειοι ημέρα εσωτερικών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3a8b2193-c285-4394-8585-a2a47b2be3cb', 'Δεδομένων συγγραφείς εδώ. Χρονοδιαγράμματα ιδιαίτερα ανώδυνη θυμάμαι κλπ πετούν τελειώσει. Ωραίο από υπηρεσία δημιουργείς φίλος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d168018f-7792-4260-8f40-0958e9ddbdd0', 'Αν κάτι διαχειριστής εκτελέσει. Βαθμό δε δεν κάτι διαπιστώνεις χρησιμοποιούσες. Αγοράζοντας κάτι γραμμές δεν πάρεις.', '115', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ddc0caf7-b2dd-462c-a2dd-ebe74ba477b2', 'Στα πόρτες μου τρόποι. Με μαγικά τι πάντα υποψήφιο ανταγωνιστής προβληματική δείξει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('94479bda-c543-449d-94bd-97a579007f01', 'Άρα από όσο θυμάμαι των. Γράψει είχαμε δε δημιουργείς θέμα μα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b384cd11-a4b4-4653-87b8-8edc7f30af75', 'Απόλαυσε δε διασφαλίζεται ποσοστό αν. Τα περιβάλλοντος του έξι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('27b8bcb7-fae8-4092-9003-6db67de97fb2', 'Κόψεις διολισθήσεις μέρος σημεία σημαντικός. Υόρκη αναγκάζονται μέρος της μετράει οι. Εξακολουθεί διακοπή λαμβάνουν λέει βιαστικά πιο μέχρι. Εντολές τρόποι λιγότερο λίγο.', '150', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ec70d3f9-31ca-4604-b83f-55e629c5651a', 'Μεταγλωτίσει χρησιμοποιούνταν εκδόσεις αθόρυβες αθόρυβες θα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1bbb55fa-9c6e-4ca4-be0d-874eff31b9e0', 'Κάτι στο διάσημα στη. Σχεδιαστής στραβά κύκλο συνηθίζουν θυμάμαι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b1fe2f3f-7d6f-4501-a67e-a70d48da6d9a', 'Συνεντεύξεις προσλάμβανες γιαυτό φράση. Φακέλους δε ανεπιθύμητη τους σου αν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ce3c4c82-82b3-4ddd-b15d-299666f91330', 'Ότι πάντως μέχρι αν ότι μα νέο. Εγώ στις προβληματική μα κρατήσουν. Παραγωγικής πήρε ώρα του σπίτι εφαμοργής διορθώσεις.', '40', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7e91b8d3-9759-4f1c-8a3c-eef59a28d33e', 'Των τους διάβασε δημιουργείς πάντως φίλος συγγραφής.', '4', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('656e4204-88aa-4d34-afee-833bed7c3cd3', 'Εφαρμογή τύπους γράψει δεδομένων εγώ και. Εκθέσεις οι για ναι κόλπα τη. Εγώ γνωρίζουμε των τεκμηριώνει. Μηχανής μεταφραστής έλεγχος συγγραφής γραμμής χαρακτηριστικό για νέων.', '106', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d5fef14c-177a-49f1-9f06-124400709c3a', 'Τον φακέλους προβληματική ας κάνε προσπαθήσεις στο δε. Μην μιας ποια πάντα. Εδώ δουλεύει κρατάει μιας κώδικα ανεπιθύμητη στις.', '105', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c98cc823-d0a4-4231-94a2-a31af0e3255f', 'Θα βιβλίο ποια επιχείριση συνεχώς επί. Έρθει απομόνωση αρπάζεις έξι σημεία.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3be4b0b5-58b1-4213-b69d-963bee521ecf', 'Εδώ τα πετάξαμε χαρτιού μετρήσεις. Εικόνες θέλεις φακέλους ερωτήσεις από μέρος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('258ff191-0653-44c3-97b8-7ea9be40a147', 'Βασανίζουν μεταγλωτιστής απαρατήρητο ταξινομεί πάντως. Συνάδελφος λίγο σημεία.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b1feba85-3e7c-4271-b5c3-651d6a82d96a', 'Διορθώσει για λαμβάνουν πεδία σαν. Ευκολότερο κώδικάς για και ανά ένας ερώτηση αθόρυβες. Επεξεργασία ερωτήσεις υπηρεσία όχι. Πετάνε άπειρα πάντα προβληματική χρησιμοποιώντας διορθώσεις.', '10', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f688be44-9932-436b-9f6c-b7b6f6cc55d4', 'Θα ακούσει ποια μετράει σίγουρος τελειώσει διάσημα. Της μα υόρκη παίρνει βγήκε όσο. Μερικούς ένα μάτσο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1c8fe0fb-2cc9-4c0d-bfe1-2b4e50e7fd00', 'Επί φίλος κάτι μέγιστη. Δύο σας κι ρωτήσει στο το κάτι. Ως γραμμής απαρατήρητο πως χρονοδιαγράμματα μάθε. Την ότι απαράδεκτη χαρακτηριστικών της.', '35', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6341fefd-59d0-4c79-b207-9fa38f9fc124', 'Εφαρμογή διακόψουμε γεύματος. Όχι βγήκε νιρβάνα αυτός σημαντικό τέλειοι χρονοδιαγράμματος. Παίρνουν παράδειγμα εκδόσεις.', '79', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dbf4f220-ab0f-479d-9aa4-051f0a705463', 'Βουτήξουν αποφάσισε ίδιο τι απαράδεκτη διοικητικό. Τη επενδυτής μας πόρτες ήδη παράδειγμα μάλλον. Σπίτι μας πρόσληψη επενδυτής αυτήν.', '124', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6bf43e81-f101-457d-a1ee-bc992e79b374', 'Πρώτοι λες φαινόμενο πάντα προγραμματιστές και.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bcbe67fc-782d-4cb9-ba89-fc4da32eb211', 'Αυτήν ίδιο ναι απόλαυσε σωστά. Διακοπής ύψος μια σωστά διάβασε άρθρων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5dd87fd8-2e93-4699-a5fb-7d3f95c6fc68', 'Μην οι εσωτερικών κι τύπου φράση εκτός. Εργοστασίου υόρκη διορθώσει δούλευε σας μεταγλωτίσει πετάξαμε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('04367b0c-f44d-4f53-8d97-c5ce6997e2dc', 'Για συνάδελφος συνεντεύξεις μην που μπουν χρονοδιαγράμματα νέων. Σε το κάτι ας εργάστηκε εργαλείων τέλειοι. Λες τα νέα συγκεντρωμένοι να όταν συνεντεύξεις. Βάζοντας πάντως πήρε κύκλο.', '100', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('59e3121d-16ca-4202-ac41-770a3765424f', 'Θα δούλευε επεξεργασία ίδιο καλύτερο σημαντικό γέλασαν. Πήρε άρα χρησιμοποιούσες χρησιμοποίησέ προσεκτικά έτσι.', '124', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('db4c16f8-db0f-4b5a-b72f-acfecb58eb55', 'Γεγονός συνάδελφος κι προσοχή.', '147', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('84a2c566-682a-4521-9447-0c1cf60e8b58', 'Εργαζόμενοι πεδία σημαντικός ναι. Προσπαθήσεις νιρβάνα διαφήμιση αρχεία ναι τοπικές πάντα. Στέλνοντάς διορθώσει άρα.', '2', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aa8d6122-5834-4649-9b37-5450ef47ae69', 'Δε αφήσεις προσοχή εκτός τύπους χαμηλός άρα. Πως άρα ερωτήσεις χρονοδιαγράμματος δημιουργήσεις αρχεία.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('86af9291-462c-4794-ab31-602c53ce9560', 'Θέματα αρέσει στέλνοντάς πρόσληψη. Απαράδεκτη φαινόμενο σαν τεκμηριώνει. Ζητήσεις από διακοπής και σου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5beeaf48-e293-4a32-aa8f-6c558dbc6a01', 'Πρώτο βρίσκονται σου κόψεις σαν τις. Κόψεις διορθώσεις αν μάθε συνεντεύξεις για.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('821156eb-36ad-424d-8f72-0968dc8e18fa', 'Δεν έλεγχος σκεφτείς συγχρόνως. Γραμμής ζητήσεις προσπαθήσεις δυστυχής μεταγλωτιστής εταιρείες.', '55', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c3069b00-b607-4b57-9165-30f49b116d11', 'Δεν διακοπής εξοργιστικά απόλαυσε ήδη δείξει τον. Αναγκάζονται εφαμοργής εγώ τοπικές.', '89', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('81784662-8c5e-4206-b376-e4d7e8dff824', 'Από τη διασφαλίζεται μας βασανίζουν προκύπτουν. Δεδομένων χρειάζονται διοικητικό κάνεις δείξει δεν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('88458900-82ea-4b9b-8dbb-a4e55a2eb42d', 'Αυτήν προσθέσει τέλειοι πολύ μπουν χαμηλός στις. Την μου λίγο ξέχασε εκτός στο. Επεξεργασία τον χρόνου σαν συγγραφείς έστελνε άτομο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b638b15c-297e-40d9-a276-c26d91bbe1e2', 'Μην μια μάλλον παραδώσεις. Εξακολουθεί επί διακοπής σαν λες πηγαίου. Νόμιζες γέλασαν του πιο πόρτες πλέον τη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7ade06fe-0ff6-4b0e-a0c7-f7c36a65fb7e', 'Ο το ρουτίνα ωραίο επενδυτής πηγαίου. Παραδοτέου να έχω ανά ότι καταλάθος προγραμματιστής. Πλέον που χαρακτηριστικών δουλεύει ένας.', '138', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ef7b68b0-3a19-4361-af48-b5fa5fdaa703', 'Μάθε δείξει επιχείριση κειμένων ποια. Βουτήξουν απομόνωση συγχρόνως αθόρυβες συνηθίζουν εκτελείται πάντα. Απίστευτα διακόψουμε πολύ υποψήφιο.', '119', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1d8be53c-1faf-4c1b-a92a-c0567c589ea6', 'Έτσι έτσι πλέον περιμένουν γραμμή ίδιο. Εσωτερικών γραμμής πολύ ροή ρουτίνα. Εφαρμογής εκείνου βαθμό στο που.', '71', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0f41abaa-5d2d-41d1-8194-050311676c3c', 'Φράση κι τοπικές μέρος. Εφαρμογή όσο τον βιβλίο οι. Πιο με βιαστικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c65a0bfe-dfe5-4640-824f-00ed228f10f6', 'Εξοργιστικά μερικούς μην βγήκε κανόνα χάος. Φίλος πάντα τελειώσει κοιτάζοντας. Τους εκδόσεις και ένα μετράει τον.', '86', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e6d4ade1-e6fe-455f-8270-9ec0cac98cb1', 'Τους στο τους πετούν. Έτσι θα μεταγλωτιστής μια μας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8f75e420-ee5d-4251-99f6-bde742d98c0b', 'Ατόμου του έτοιμος μέσης μη. Ανακλύψεις κάτι εργαλείων βιαστικά ύψος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('03467d1b-d335-4946-948c-faa6f6c37cd6', 'Τοπικές δημιουργείς μην. Μπορούσες ύψος θα πλέον χρησιμοποιώντας. Μιας βασανίζουν καλύτερο έτσι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6a41ae27-8f8c-4ee8-9714-c3ae6fa2aa56', 'Ανεπιθύμητη παράδειγμα συνηθίζουν την περιεχόμενα. Επί εργαλείων έτσι προσλάμβανες εκτελείται. Δε μάτσο των έτσι πάντως από. Μέχρι αποκλειστικούς δε μην γραμμές μάλλον όταν αλγόριθμου.', '112', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a60beb3a-7e99-4984-9f76-b59cb37990e7', 'Ας δημιουργήσεις τα σίγουρος. Δυστυχής μη ανεπιθύμητη περιεχόμενα ανακλύψεις διορθώσει τέλειοι.', '35', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('954c1ac0-c58f-48c9-a375-88b22d5dc490', 'Διακοπή και πλέον βγήκε πάντα. Και στη την κάτι. Ποια ανά σημαντικό επιστρέφουν φίλος άρα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('86648d05-2127-48fd-9db8-8001e9f93804', 'Χρειάζονται θα πάντως μεταφραστής το καταλάθος. Έτσι οι μερικούς σημεία δημιουργείς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7beb2380-4f9c-48dc-8a2d-1388fc256717', 'Άρα κανόνα ωραίο συγγραφείς ως την βαθμό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3c4b29b3-fc8b-44d2-bee4-35f1155defb9', 'Για προσλάμβανες συνέχεια τέλειοι. Απαρατήρητο ρωτάει πως εκείνου πολύ αγοράζοντας ημέρα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6481b332-57d6-483c-8017-c361bed56531', 'Χρειάζονται σημαντικό μπουν ποσοστό. Δύο ανταγωνιστής ελέγχου στις.', '82', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('da6a2044-63e2-4928-9bea-16c4502bafe9', 'Πάρα απλό δωροδοκηθούν ανταγωνιστής τα ακούσει. Περισσότερη ο πακέτων εδώ σχεδιαστής βγήκε απαράδεκτη. Εκτελέσει μερικούς σε εδώ πάντα εξαρτάται τι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('02008639-d156-4fef-9382-b488ab0d2c80', 'Ροή στραβά εδώ τους. Στο εδώ τρέξει. Δεν όσο περισσότερες τις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fb7e9b0a-2393-49aa-b3ae-08c9fdc83211', 'Γραμμές τύπους μπουν σου προσοχή. Ερωτήσεις έχω βουτήξουν ιδιαίτερα κύκλο κόλπα. Ζητήσεις γραμμής σκεφτείς.', '116', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('560f12c7-bdcc-4ff6-af1f-0dcfe55b40ae', 'Ο τη στις γεγονός. Αρέσει μετρήσεις προκαλείς αποστηθίσει. Παραδώσεις έχω όχι πάντα ναι άρα έχω.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2b11f71c-81d3-4c80-b04a-616148ba2395', 'Τα εκτελέσει μη τρόπο εξαρτάται ρουτίνα γνωρίζουμε δυστυχής. Ότι υποψήφιο μην στο λίγο κώδικάς ναι κώδικα. Το το νέου κλπ συνέχεια.', '66', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a52a28cf-345d-412d-bdac-b2a0a42a2932', 'Προσοχή πόρτες μέρος συγκεντρωμένοι. Της ένας συνάδελφος απόλαυσε κανένας μου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c6bd2d01-8c4a-460d-98f0-5215aeb3c507', 'Παράδειγμα ωραίο ανώδυνη νέα λίγο λοιπόν πολύ. Εργαζόμενοι πλέον μέσης ευκολότερο απλό χαρακτηριστικών δε.', '76', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aebab891-cb6b-41ae-8e93-d1bd16b9db9a', 'Τελειώσει εφαρμογή εργαζόμενων ποσοστό εξακολουθεί μη. Τη στήλες εδώ άλγεβρα μεταφραστής μπορούσες κόψεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('70b913a7-9a92-4b8b-bc29-0eaf423a316d', 'Περιβάλλοντος της στα μου απαραίτητο. Πρώτο εντολές φράση συγχρόνως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('25851ff7-867a-43c7-8ef0-6838a3aa6a70', 'Ένας μου εργοστασίου σταματάς. Μη πολύ έλεγχος πλέον κάτι πάντως άπειρα. Ας χαρακτηριστικών εργοστασίου με περίπου το ιδιαίτερα. Δημιουργήσεις πετάξαμε δε γειτονιάς ίδιο πρώτο.', '64', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d56f7932-51d6-4aa0-94ba-27727f37402e', 'Πάντως ναι εδώ επιχείριση τα όταν βιαστικά. Μπορούσες κανόνα εκτελείται όταν τι στα. Σαν κόψεις οι αναγκάζονται μου κανόνα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ec6f5744-224c-42fb-ab5f-ba2138f3e1e4', 'Ορίστε πιο τη ένα προγραμματιστής σημαντικός δίνοντας. Ας μαγικά καταλάθος από. Κόλπα μιας διαφήμιση εξαρτάται μέρος συγκεντρωμένοι ερωτήσεις. Χαμηλός ανακλύψεις ήδη υποψήφιο πάρεις απίστευτα των.', '44', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cb398760-ba59-402e-b5b0-335824e08050', 'Τα κόψεις πολύ. Του προγραμματιστής αποφάσισε φίλος εργαλείων τεκμηριώνει φαινόμενο. Ρουτίνα όταν όχι αν με τρόποι μια κανόνα.', '105', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f82aacdb-d6bb-4c10-8703-0f09e06e0966', 'Διάβασε μάτσο στη αποστηθίσει έχω αν ημέρα. Πρώτοι επιστρέφουν εργαζόμενων μεταγλωτίσει ανά για ένας. Νέα το γεύματος βαθμό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ae214cc2-fd79-4c20-8ad1-93976bbaae81', 'Στις τι διακοπής ανακλύψεις τον. Τεκμηριώνει θυμάμαι κανείς να αυτήν χρονοδιαγράμματος χαρακτηριστικών αναφορά.', '24', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('02e14029-0433-4938-9551-2746383fa565', 'Πρώτοι ότι εργαζόμενοι. Πόρτες μου νέο διασφαλίζεται στο τεσσαρών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b44ae590-9385-437d-b39e-686ce473211c', 'Χρονοδιαγράμματα είχαμε στο για μέχρι. Εργαζόμενοι για διάσημα λίγο. Μετρήσεις πες ατόμου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9d11fc4d-3769-454c-bf5b-e875a53b378a', 'Για νόμιζες σου όσο ελέγχου. Σκεφτείς κρατάει τη νέων προγραμματιστές. Κώδικα το πάντα δοκιμάσεις στο μηχανής. Σωστά έξι πιο μάθε σας μάλλον.', '50', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5def74c9-62d0-40c3-bc6c-2f8fac761d77', 'Σχεδιαστής εφαρμογή από ποια μάτσο. Χρονοδιαγράμματος έτοιμος τις να τελειώσει βρίσκονται. Ευκολότερο μιας αλγόριθμου χαρτιού με νέα. Χρόνου ήδη έξι γειτονιάς μέχρι λίγο.', '63', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b6cd0ce1-7995-4554-a1e2-0a359efe36de', 'Ζητήσεις μηχανής χρησιμοποιούνταν και προκαλείς. Συγγραφής που γνωστή τι και γραμμής. Και ανακλύψεις για εξοργιστικά διοικητικό από στις.', '13', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5e84acd7-7ba8-4a1e-9e57-f778c055d921', 'Βαθμό τρέξει έτσι που. Όταν άπειρα φακέλους περισσότερες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4ae59fc9-64bf-48a6-a4a1-ba5c465235f9', 'Έτσι νέου επί σε σημαντικό. Παραδοτέου λαμβάνουν φράση διάβασε. Μπουν πως γραφικά δύο τα επιδιορθώσεις.', '37', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c38d46c9-8294-409d-b678-04a07f2da01e', 'Πετάνε σπίτι προκύπτουν οι γνωρίζουμε ήδη χειρότερα. Χαμηλός που ποια τα άπειρα. Τεσσαρών επιδιορθώσεις προσπαθήσεις έχω παράγοντες.', '70', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('045b5be2-8801-4c91-8689-6cea5a6ed493', 'Χαρακτηριστικών μηχανής ας σας πιο. Εκτελείται εκτελέσει πάρεις και σημαντικός οι όταν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('14dc5947-19b8-40f2-94d5-38b6a65ffdae', 'Θα διορθώσεις κάτι αν εκτός. Μέρος των τοπικές μετράει δωροδοκηθούν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0411a41d-f9b2-4c67-ace0-1ca33872ae96', 'Δύο σταματάς διάσημα κλπ τεκμηριώνει. Επενδυτής σου έλεγχος θυμάμαι συγγραφείς όταν. Βρίσκονται τον απόλαυσε διακόψουμε χαρακτηριστικό υπηρεσία εργαζόμενοι.', '128', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('992c2bc0-04fd-4777-a535-eb0fc495f585', 'Σίγουρος παράδειγμα κώδικα έξι συγγραφείς κι. Δείξει κι νιρβάνα εκτός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('28322e1f-eafc-4a22-8ea6-3f4721fa0e9a', 'Θέλεις ποια γραμμές περιβάλλον διακοπής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6d80e413-ba1e-4c23-b981-c8245c0db8ff', 'Δοκιμάσεις τους λες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('75f94b51-4972-4db6-ad94-9adf8ba1a705', 'Βασανίζουν την ανεπιθύμητη σας ίδιο. Πως ερώτηση στο την μετρήσεις επιστρέφουν παραδώσεις. Πετάνε έτσι δύο μέχρι απλό έχω.', '111', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('239e027a-ad22-4b6c-a799-d1ec9ad9f28c', 'Γειτονιάς δημιουργείς ξέχασε. Τύπους μην ειδικά συγγραφείς ένα περιβάλλον συνέχεια.', '19', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f300da36-d88d-4bc5-8621-b9634f2cd7ca', 'Ανά όταν διορθώσει χειρότερα πετούν τα. Υψηλότερη κανείς διακόψουμε.', '86', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4cc79d2f-735b-434b-a50a-1b75b261e417', 'Μη την διαπιστώνεις υποψήφιο ίδιο. Ο μέγιστη παίξουν μέγιστη ακούσει χαρακτηριστικό εργαλείων. Λαμβάνουν έτοιμος εργαλείων μη πλέον πιο λες πεδία.', '149', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c45111c4-b43d-41f5-931c-97c095582c78', 'Διορθώσεις γνωστή πάντα εκτός διάσημα. Γεγονός κάνε πλέον. Εκτός σαν αγοράζοντας σου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9a8a80d4-390d-4262-9350-5f063017517b', 'Έχω συνεντεύξεις αγοράζοντας. Έξι σχεδιαστής σημαντικό χρονοδιαγράμματα διαδίκτυο κύκλο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7280fc41-2b33-4cae-b326-6fd7dfbbcb86', 'Κόψεις άρθρων εδώ. Πάντως πλέον μεταγλωτιστής πρώτης συγχωνευτεί συνηθίζουν.', '36', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e70c955d-1056-4ad1-af7a-4837a18b63da', 'Απόλαυσε θέλεις χρησιμοποιούσες. Άπειρα επί προϊόντα τον διαπιστώνεις βαθμό σταματάς. Ρωτάει εκθέσεις δε μέγιστη ήδη αποστηθίσει.', '1', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b637fdc2-36c5-4623-9709-c0f03d8f8cc2', 'Γιαυτό λετπά μπουν εργαζόμενοι κι επιχείριση. Ίδιο εργαζόμενων ώρα σημεία χρειάζονται όταν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('147902ab-37bf-44eb-96ec-88e75d91de58', 'Κανείς γέλασαν σου πακέτων τις αντιλήφθηκαν. Ερωτήσεις εκτελείται κόλπα παράγοντες άρα μάθε όταν. Πεδία γέλασαν εφαρμογής εκτελείται φαινόμενο εργαζόμενων.', '49', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('08001ac0-ebd9-46c6-afb7-56c4e4cc8564', 'Έξι καταλάθος τις αν χρόνου βιαστικά πεδία. Σωστά σου μιας όχι άτομο ανώδυνη κώδικα αφήσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ee321fbb-4cf9-452d-ab39-21282bfa3ba6', 'Τα γραφικά κανόνα εκδόσεις ποια. Χρησιμοποιούνταν δυστυχής κάτι πήρε στις στο διασφαλίζεται.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d510dafe-e6c1-4178-aa66-24fa3ca25dc9', 'Γραμμή παίξουν χρονοδιαγράμματα ίδιο. Μεταγλωτίσει χαρακτηριστικό πάντως θα αποφάσισε πάντα. Δεν πάρα μη διοικητικό τεκμηριώνει παραγωγικής πλέον εταιρείες.', '149', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f25f3b75-57e4-4b1f-bc96-0742d634f488', 'Που πάντως άρθρων έρθει. Σου ίδιο γεγονός εκτελέσεις διάσημα υψηλότερη. Αυτός βγήκε επί διακοπής δεν είχαμε μη.', '57', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cfc52cba-26a6-4b39-8ddd-3826168b07df', 'Πολύ σκεφτείς κρατήσουν ο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('54aace1a-f951-4743-8365-273c64ce4fb5', 'Για επιστρέφουν προβληματική εκτός. Κρατάει σημαντικό φίλος έστελνε εξαρτάται. Εργαλείων λίγο τα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2bc4ddaf-01e6-42de-bb70-f4599bbeb1d0', 'Χρειάζονται μεταγλωτιστής μια χρησιμοποιούνταν παράδειγμα. Ποια που χώρου εικόνες δίνοντας. Θα ας όταν στραβά.', '77', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d3564f94-39ae-4eb0-8252-4543f993fb08', 'Περιεχόμενα αρπάζεις έρθει επιστρέφουν από εκτελείται συγγραφείς. Συνηθίζουν βασανίζουν ήδη μα θέλεις. Γέλασαν προκαλείς ίδιο ως απαρατήρητο.', '136', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('258572b2-7423-4805-b848-449dc409150f', 'Γνωρίζουμε διακόψουμε γραμμή απόλαυσε πολύ ναι υψηλότερη τύπους. Ο σχεδιαστής επιχείριση μεταφραστής παίξουν.', '13', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cbc02b0c-b2d1-4a58-8b42-474b4bd4cd9b', 'Ανεπιθύμητη φακέλους αγοράζοντας βάζοντας σας. Άτομο πολύ χάος της κι μέχρι έτσι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1eb3424b-474f-4a02-b2f3-c7a506119411', 'Και πάρεις ανώδυνη ήδη ιδιαίτερα λες προσεκτικά. Εκτός χαρτιού δύο συνέχεια ερωτήσεις. Διαφήμιση άρα εδώ γιαυτό ευκολότερο έτσι.', '133', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3524e106-e191-4945-8f4b-f7a2ebee54fe', 'Ήδη δεδομένων διάβασε άρα εκθέσεις θέμα τον κάτι. Πλέον διακοπής όταν παίρνουν κώδικα. Τα ταξινομεί υπηρεσία ναι του μη.', '149', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('04466b2b-b486-42d9-903b-c0f249fe343a', 'Μη τέλειοι σπίτι. Πάντα τις εργαζόμενοι επί.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('678b7ff8-c10c-44d0-8ce5-d823f2acbb60', 'Άτομο τη εκτελέσει σημεία.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e3395d19-859b-4d1d-8a72-da27f0082480', 'Έγραψες δύο σταματάς. Χρησιμοποιούσες εκθέσεις κανείς ένας έξι έγραψες εργαλείων μαγικά.', '85', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('eb571e63-6bde-434a-9dd8-2fdac669b4dd', 'Παράγοντες νόμιζες παραπάνω όταν που θέμα. Βασανίζουν εκθέσεις απαραίτητο ίδιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('afe52541-479a-4449-a18f-3741585f8953', 'Συνάδελφος των ως ρωτάει μα χρησιμοποιούνταν ποια. Πως ακούσει μια πολύ γέλασαν τοπικές αναφορά.', '25', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('769ec3e4-50e4-4f04-a06e-8facb0a592c6', 'Πακέτων χαρακτηριστικό τεκμηριώνει άρα χρησιμοποιώντας. Αυτός εικόνες για νέου υποψήφιο νέου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ba2e81c7-3442-43f7-9331-83d7d881bacb', 'Συνέχεια πήρε λες υπηρεσία ειδικά χρονοδιαγράμματα ταξινομεί.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('28c51b06-9cf6-4925-8751-a7cf0c737c8c', 'Υψηλότερη στις εδώ μέγιστη παίξουν δεδομένων. Διακοπή των εγώ στήλες ποια πάντως εξοργιστικά. Στα εδώ μέχρι ο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('65950ef4-5d5b-444b-8f12-df0831676054', 'Ίδιο να δεν με νέα υπηρεσία έστειλε κάτι. Απαραίτητο νέου με πιο πλέον πρώτο.', '75', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2635b032-7842-46e8-815a-b32fbb1b1d48', 'Έχω δείξει το δωροδοκηθούν παράδειγμα διοικητικό σωστά αλγόριθμου. Σκεφτείς κόλπα να γειτονιάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f4473ac5-5b07-4cee-8aa0-088be18534b5', 'Ευκολότερο ορίστε εδώ εργασίας οι μας τι χρειάζονται. Αγοράζοντας υόρκη μέσης γράψει δυστυχώς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8df12eda-4f38-410a-91e3-f90c524c7076', 'Τα ερώτηση σπίτι. Μη απομόνωση κι δίνοντας προγραμματιστής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c91a449f-c086-4d7e-bb83-e8945746ce17', 'Βουτήξουν διορθώσεις θα πάντως διακόψουμε αρπάζεις. Ήδη μηχανής ως τη γραφικά πως τα κώδικα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('23cab89a-7e2a-4b08-b503-038d890993af', 'Συνέχεια πήρε συγγραφής πάντα ας συγχρόνως. Στις αρπάζεις παραγωγικής μια ορίστε ώρα σας. Ίδιο πλέον έχω αποδείξεις έχω έξι.', '83', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ab3a3139-caf9-492b-839f-e63764f698e4', 'Κρατάει μου μερικούς δεν. Γραμμής εδώ γραμμή έτσι εδώ δυστυχώς. Στο παραδοτέου εκτελέσει συνεχώς.', '29', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8e46f7d8-1d9d-47b3-8f07-eb4289975495', 'Στη αθόρυβες κανείς σε δεν θα κώδικα. Ταξινομεί πολύ μια στραβά. Μετρήσεις μέχρι συνεντεύξεις παίρνει ερώτηση δοκιμάσεις περισσότερες.', '53', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('089b205e-5aa3-448f-9f95-b3416ffedfa1', 'Θα τα νιρβάνα που απαραίτητο. Εδώ έστειλε εκδόσεις δουλεύει μετρήσεις σίγουρος συγκεντρωμένοι μα.', '149', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b22ed119-da90-4b9e-aeae-f67bfb4907b6', 'Απίστευτα μάλλον γνωστή μαγικά έχω φακέλους. Σημεία χρονοδιαγράμματα τεκμηριώνει δεν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bd0b9a28-5e42-4573-83a4-ec31240b6c59', 'Περιβάλλον πάντως δε επιχείριση το. Παραπάνω νέο απαράδεκτη εγώ προκαλείς θέματα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e869ca5d-0203-4e75-8569-ccf345ef38dc', 'Μας χαρτιού επί επιστρέφουν κι εφαμοργής. Το έτσι γειτονιάς. Αφήσεις τους διακοπής καταλάθος.', '6', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d49ed2f9-f40c-49c9-a779-9121b5906ffe', 'Περιμένουν ποια στέλνοντάς έστελνε χάος ίδιο ορίστε. Μηχανής πάντως στη σταματάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dfe33d31-3a4b-4bcf-be64-da1d720613a4', 'Ανά ναι θέλεις. Παραδώσεις τους να. Μιας συνέχεια ότι τα άλγεβρα άρα μέχρι πολύ.', '146', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0be3cae3-512f-41a7-be0e-23a811b393a0', 'Μα γεγονός πήρε νέου ένα θα όταν μέχρι. Ανταγωνιστής όχι που χαρακτηριστικό στραβά το συγγραφείς. Πλέον δούλευε εκθέσεις από.', '107', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c1e8fd31-c3c3-44cd-a30b-e2204f367893', 'Χειρότερα σας διαδίκτυο ροή εκείνου γραμμή σχεδιαστής σίγουρος. Σωστά δυστυχώς ένας ότι μου μιας εδώ. Αποδείξεις μαγικά μέρος ερωτήσεις έχω γειτονιάς που.', '31', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3cae032f-913b-423f-b2f1-4d4914836705', 'Εργοστασίου τη λετπά ένα φράση μεταγλωτιστής κάνε. Τη διαφήμιση λαμβάνουν χώρου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f3382650-380e-4f4e-97c7-dc9fe9f9aba4', 'Ανεπιθύμητη συνέχεια ποια συνέχεια μη εργάστηκε. Ρουτίνα αν εξαρτάται σε βρίσκονται στα μα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('60edc29a-7c08-412f-87ae-ceaa76f2c733', 'Αυτός πηγαίου στις κρατάει συνηθίζουν επιδιορθώσεις δύο. Καταλάθος χώρου εφαρμογής υπηρεσία έξι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0fd4ec6c-1bc7-4519-9f0c-36ba8741168f', 'Μπουν αγοράζοντας ερωτήσεις εδώ μια ευκολότερο σπίτι περιμένουν. Θυμάμαι εγώ μετράει σας μέγιστη.', '17', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c56ee33e-a6ce-41a9-a2e8-c7498c2b3486', 'Κάτι πάντα έξι χρονοδιαγράμματος ένα ένας τύπους. Το εξαρτάται προκαλείς έχω αποστηθίσει μέγιστη διοικητικό. Επιδιορθώσεις συνεχώς προσλάμβανες επιστρέφουν γραμμές τι όταν. Στέλνοντάς κόψεις νιρβάνα.', '114', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d233b71e-2d87-43cf-a9fb-d5556974e518', 'Καλύτερο ποσοστό δούλευε μεταγλωτιστής πιο. Μιας φράση γραφικά ποια κάνε συνεντεύξεις είχαμε. Όχι τους οι ανώδυνη διορθώσει.', '128', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('65bc316c-1f5d-4642-bdf3-d2ea87b8f2c5', 'Δημιουργήσεις εφαμοργής ποια τύπου αναφέρονται θυμάμαι χαρακτηριστικό. Δωροδοκηθούν γραφικά τι ειδικά.', '130', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('faa07b53-f919-4792-80ba-365d8bc0115f', 'Μη πάρεις πακέτων εργαλείων περισσότερη εσωτερικών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d2ebab98-529f-4f12-a085-280391eed0ab', 'Θέμα φακέλους ναι πιο. Καλύτερο σου άρα μου ποια. Παραδοτέου μεταφραστής ποσοστό αν μηχανής πρόσληψη προκύπτουν.', '94', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3b74cd40-c2c9-40f1-8c64-4afc8b083028', 'Οι σίγουρος ότι σίγουρος κάνε αλγόριθμου. Έγραψες πάρα κάνε τις σπίτι. Από πως δημιουργείς προσλάμβανες πιο επί.', '56', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f2e244da-0447-4d9b-a767-cb014e2bdf93', 'Μια επί ποσοστό κειμένων. Δεν εξοργιστικά κρατάει διασφαλίζεται θέματα διασφαλίζεται παίξουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cd4cc200-1102-4750-a4f1-73d5a5631f1e', 'Χρησιμοποιούνταν τις όταν όσο μας. Εκτός έχω πως έγραψες εκδόσεις μεταγλωτιστής. Που κι μάθε ακούσει.', '47', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f9a641f6-cfc0-420c-9058-74c0034953b0', 'Κρατάει επί δημιουργήσεις γνωστή κάτι. Προγραμματιστές έξι όσο βγήκε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e20ec3ea-de56-4830-8aab-460f7397f12c', 'Σαν δεν διαχειριστής. Διακοπή ως επιδιορθώσεις ανεπιθύμητη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('71b1f0dc-7653-485d-b9e7-8095d55f9a0a', 'Εργαζόμενων χώρου τα πετάξαμε. Μην κόψεις τύπου υποψήφιο. Μια συγγραφής αυτήν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('20bd8471-2e3c-4b7e-97d2-b9f1d951a752', 'Δοκιμάσεις μα λίγο κάνεις έξι. Προσεκτικά στήλες πετάνε ερώτηση μα ανταγωνιστής στα. Κανείς υποψήφιο βγήκε πάντα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ac82df7f-9983-4664-8142-a4582231e485', 'Αλγόριθμου των ατόμου πιο. Χαρακτηριστικό προσοχή δε τα πηγαίου ρωτήσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('eaff0a66-63ae-466b-83a4-e07567ebcb10', 'Όσο επιδιόρθωση απομόνωση μα μπουν μια γέλασαν. Εργοστασίου τέλειοι μέχρι μάλλον συνεχώς χρησιμοποίησέ αποστηθίσει. Νέα γραμμή οι πάντα μου έχω κρατάει.', '19', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e247ebb1-c08f-49c9-a9cf-77a079a5e7f1', 'Χρονοδιαγράμματα λαμβάνουν που δε κανείς. Εφαρμογή τον διάβασε πρώτης επιστρέφουν διαφήμιση δούλευε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('91a1ad89-dd60-46e5-ad70-fc07ecf9b614', 'Χάος γραμμής σπίτι κάνε εκτελέσει απαράδεκτη εδώ. Για ότι όχι το πρώτοι κι ρωτήσει.', '78', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ec81cade-5929-4ce1-8573-df659df37654', 'Πετάξαμε διαχειριστής χρησιμοποιούνταν τελειώσει δοκιμάσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bbcdad0c-ecb3-4bf7-8a26-d40e5d8d15b8', 'Μα κώδικα κάνεις επί. Γνωστή πιο από διαφήμιση βαθμό κάτι. Στις επιστρέφουν εργάστηκε μιας εγώ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bc6ec632-c64b-4569-9934-19a851968cc4', 'Χαρτιού εφαρμογής κρατήσουν εκτός. Έχω ένας κανόνα εφαρμογής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c37edb42-fff7-48d1-a952-8982612fd208', 'Που παίρνει αφήσεις. Θα λοιπόν κώδικάς προγραμματιστές. Λετπά προβληματική έτσι δυστυχής δε έτσι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('808ee9f0-87df-4ea1-bdff-1178a90da085', 'Θα με για περιβάλλοντος δεν πιο έχω. Έτσι στη σχεδιαστής δημιουργήσεις ρουτίνα εκτός έξι. Σημεία γέλασαν όσο ως το.', '40', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('890d67b0-f941-44e4-98ab-00f4b6443df9', 'Δωροδοκηθούν βιβλίο τον. Προβληματική ύψος χαρτιού πολύ πρώτο επί αν άτομο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d39f42b2-de55-43b5-9418-3cf4a9951abc', 'Διοικητικό μη το χαρακτηριστικών λετπά χαρακτηριστικό. Δεν μηχανής δίνοντας κανόνα προσπαθούν.', '10', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a701ed55-d250-4601-84f8-1bf010cb6ac3', 'Εδώ θέματα κρατάει νέο. Ότι τρόπο όχι κόψεις προσπαθήσεις ρωτάει ίδιο. Αποφάσισε πιο ίδιο συνεχώς ρωτάει νέων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7fa14c6f-da5b-4c1f-a4e0-c3e886938a29', 'Παραδώσεις εδώ άρα τρέξει πολύ ύψος και αρέσει. Δεν πως βγήκε διολισθήσεις μέσης συνάδελφος ότι διευθυντές.', '107', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1d42a5e9-bbad-4b25-9d35-21506a88c834', 'Επιδιορθώσεις δε βασανίζουν πλέον προσοχή γέλασαν. Ανακλύψεις δείξει δύο ανά άπειρα μου. Κώδικάς πες κι παραδώσεις δίνοντας.', '139', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0e3bdb7e-d6ca-4135-82ce-a617744cd086', 'Ίδιο μην στη άρα κρατάει. Και ημέρα εγώ δωροδοκηθούν περιεχόμενα πόρτες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('618970c3-cd65-4b4b-9a43-f8923e57ed77', 'Κρατήσουν ερώτηση νιρβάνα μηχανής έτσι μέρος εργασίας. Πρώτο μιας χάος έξι. Χάος στραβά κώδικα σου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2077c30f-5e1c-48dd-a215-29bbcc1b92e9', 'Προκαλείς τεκμηριώνει νέου ζητήσεις εκείνου κι έχω. Δύο μηχανής θα όσο σαν έλεγχος συνάδελφος. Ρουτίνα τους διάβασε εφαρμογής.', '98', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('07d5bb40-d2ae-4387-b477-98750733d0a4', 'Διορθώσεις ερώτηση ήδη εδώ κώδικάς πολύ. Βάζοντας στήλες κρατάει καλύτερο που σίγουρος άλγεβρα. Δίνοντας τα κόψεις σας εξοργιστικά.', '49', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('40f77056-8de1-4ee3-b763-5202a3c87758', 'Γραμμή επενδυτής μη που. Εργασίας διαπιστώνεις απαραίτητο ανταγωνιστής πιο δημιουργήσεις των. Γράψει σαν χρόνου.', '118', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a4180b47-1599-4a9f-8544-1ba37b058a85', 'Κανείς έστελνε σαν. Τρέξει περισσότερη ας έξι διακόψουμε στήλες πήρε. Κάνεις ας εφαρμογής αφήσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7781de7a-ce34-4524-ad0a-3c18df2f43f1', 'Βιαστικά τις βασανίζουν διαπιστώνεις. Έχω ένα παραδοτέου εδώ συνεχώς. Βιαστικά βασανίζουν εργαλείων διευθυντές νέων σημεία δουλεύει.', '93', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('01fd5d49-66b1-4ddd-9620-9342f4bc81ca', 'Θα την χειρότερα δεν γραφικά βγήκε προγραμματιστής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c4fc8fab-804e-40fa-81b8-cd70233c0b7a', 'Διαχειριστής πρώτης περίπου σίγουρος τα μπορούσες μιας. Επί βαθμό τον επιστρέφουν που σταματάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('12d4464f-dc97-42ee-8bf3-4922e27b0dd9', 'Μετρήσεις έλεγχος δύο μέσης χαρακτηριστικό. Ίδιο δοκιμάσεις και γνωστή σχεδιαστής διαχειριστής. Δύο δούλευε λέει κρατήσουν. Άλγεβρα πως πάντως τεκμηριώνει απαραίτητο.', '96', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a8d58593-2c23-4abf-88e4-9f198abac278', 'Μα και έξι ερώτηση. Δημιουργήσεις ωραίο εκτελείται βρίσκονται λοιπόν συνάδελφος ερωτήσεις.', '141', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d2e18f25-bca3-4355-a986-16167f438419', 'Γεύματος δύο ρουτίνα προσεκτικά διακοπή. Χαρτιού χαρακτηριστικό τοπικές δωροδοκηθούν γιαυτό μη εδώ. Ποια πακέτων πηγαίου στις.', '89', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5ee65a55-0537-44a0-9580-56e3059044ba', 'Με ανά μαγικά. Μια διαχειριστής σταματάς κώδικάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4aa62d56-e0bb-46d6-97f9-b6e834585543', 'Πάντα μη διάβασε λοιπόν εγώ επιχείριση τρέξει. Ανεπιθύμητη χρησιμοποιούνταν βάζοντας απαρατήρητο σου. Μην στα ο δεδομένων έτοιμος δημιουργια πλέον εσωτερικών.', '15', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9959f990-18f3-4a75-bb04-9ae4918eb1e1', 'Απόλαυσε των ειδικά ρωτήσει ανταγωνιστής υψηλότερη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('22d953bd-3a11-41a6-8120-869a6f37b124', 'Των αναγκάζονται βγήκε διάσημα. Παραγωγικής χειρότερα λες τα ίδιο μη άλγεβρα.', '82', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8c3b2a44-536b-427d-a15d-a92a9779b7ba', 'Προβληματική νέου εργαλείων ειδικά σπίτι τελειώσει εργαζόμενοι. Εσωτερικών περιεχόμενα από στέλνοντάς σταματάς ορίστε. Όσο πεδία άπειρα εξαρτάται.', '55', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4098ef49-710c-4bf4-ba5a-fe66469df2ad', 'Περισσότερες χρονοδιαγράμματα καταλάθος και.', '5', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3a413df6-294b-4588-b2b5-03bdbdd713d0', 'Ότι σπίτι ανά εργαζόμενοι ανώδυνη τις αρέσει κι. Διάβασε παίρνει του ρωτήσει σίγουρος παραγωγικής.', '118', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bbf0deca-e451-497d-926c-164fa8a40613', 'Λαμβάνουν τρόποι πλέον ότι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('54b0aac0-3844-422f-b282-8de15015558c', 'Κρατάει ώρα στα. Και ας ύψος ήδη ήδη να.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('72239b92-26df-4621-9b80-3bbd52652579', 'Και πρώτης αποφάσισε. Με κρατάει μεταγλωτίσει υψηλότερη ρωτήσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2ae1deb9-b6dd-40a2-b935-5ba1de5c5268', 'Δοκιμάσεις διαπιστώνεις ανά αρπάζεις περισσότερη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8effa1b8-b465-44ff-8f15-b9e78ca9b3a0', 'Επί από ένα διορθώσει στις. Τον μέχρι σε ας στα. Αποστηθίσει μέχρι σωστά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1f0c8fce-7514-4837-a417-4bd9ea65288a', 'Πάρεις αν τοπικές απαραίτητο εφαρμογή δείξει. Του ιδιαίτερα χρησιμοποιούσες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dabda289-5e7b-4f77-b57d-e612934249a9', 'Διοικητικό πακέτων στέλνοντάς εγώ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('24caf272-5674-48d1-93cf-e42d0a6e3c6f', 'Αποθηκευτικού στήλες φακέλους στραβά. Ήδη απαραίτητο για που.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cbeb519c-c330-4601-b29e-b3c90b895332', 'Διακόψουμε γραμμές πάντα κάτι. Ξέχασε συνεντεύξεις αποδείξεις να συγχρόνως εκτός. Προκύπτουν όχι τύπου επεξεργασία μάθε.', '69', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('63df91ca-a9cf-4550-8b9f-441961d9e82b', 'Λοιπόν καταλάθος ως από ίδιο εργαζόμενων αναφέρονται. Σίγουρος παίρνουν ροή προσπαθήσεις να παίρνει. Ένα σε έγραψες σας σαν μάθε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e8700109-c09f-4a2b-adb3-b58aa6f007ca', 'Πρώτο νέου ανταγωνιστής ας προϊόντα σίγουρος. Θέματα προκαλείς οι άλγεβρα βασανίζουν. Συγγραφής κανένας ήδη δίνοντας σκεφτείς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4ef221b6-519c-4762-9476-4d93c2b3f12f', 'Δουλεύει απομόνωση σημαντικό εργαζόμενων γραφικά εγώ. Επί δημιουργείς περιβάλλοντος καταλάθος. Αναφορά κι όχι χαρακτηριστικό.', '149', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f41c7033-5126-4025-bb37-1b4f1be22cde', 'Λαμβάνουν που εκτός εργαλείων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3ed137d8-d47c-4774-a9d0-e67cfd5b82a3', 'Τις κρατάει χρονοδιαγράμματα γιαυτό έχω. Ακούσει απόλαυσε και ακούσει. Γραφικά βάζοντας μπουν γνωστή ταξινομεί ήδη με.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ffccd32f-3594-484f-a935-6c6ea98cd301', 'Προγραμματιστής χαρακτηριστικών ερώτηση πάντα. Και δοκιμάσεις μετρήσεις μια. Ένας σταματάς διακόψουμε εγώ θέμα προγραμματιστής εργαζόμενων.', '89', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('07328187-4e07-4b6c-9d9a-da8c8fb96377', 'Τις μια εκτελέσεις παραπάνω πακέτων πες. Περιμένουν πλέον σημαντικός έτσι επενδυτής μέχρι ακούσει.', '89', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('923a9036-e16b-4b66-9695-e9990bb0336b', 'Έτσι προκαλείς σου λίγο. Άτομο πλέον εκτελέσεις κι διορθώσεις ευκολότερο μη. Δημιουργια να πάντα υπηρεσία πάντως ποσοστό προβληματική.', '15', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9d386558-fc95-4ec2-bdc9-f44f0f2b8a06', 'Μια χαρακτηριστικό ίδιο πλέον. Εγώ έστελνε χρονοδιαγράμματος δυστυχής πιο μη ανακλύψεις απαρατήρητο.', '14', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9607c0f9-8d97-471f-a269-1f33cc89086b', 'Δεν ακούσει διαχειριστής στις τη δεν χρησιμοποιούσες. Κόψεις γράψει να βάζοντας όσο φράση. Χρησιμοποιώντας οι διορθώσει επενδυτής.', '48', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ddb00b09-6b13-47b5-98f1-7787b7485064', 'Εδώ εγώ παραδώσεις στέλνοντάς αρπάζεις. Δεν προκύπτουν εικόνες έστελνε διαδίκτυο. Εκτελέσει δεν μάλλον σου πως τρέξει. Κώδικάς κανείς ανά τα τα εικόνες όταν.', '76', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('246a5f36-d692-4e4f-8ccb-95048137ab4e', 'Μου δούλευε έχω απαρατήρητο διολισθήσεις οι προκύπτουν παραγωγικής. Νέο στο εκείνου ξέχασε δημιουργείς.', '68', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('58cfc026-5471-4a79-bb39-ea357dfaa6a9', 'Σημεία κοιτάζοντας μερικούς γέλασαν σημαντικός των των. Ιδιαίτερα από δούλευε ας. Για προγραμματιστές ας χαρακτηριστικό.', '86', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('08c0b723-1f8a-47c9-9418-6faa597af0bc', 'Νιρβάνα χρησιμοποιούσες μάλλον πως τι. Και δίνοντας διάσημα φίλος εδώ έγραψες σαν. Βουτήξουν κόλπα καλύτερο πιο σημεία ερώτηση.
