INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '17891', '2023-07-20 00:00:00', '2023-09-13 00:00:00', 'Προσπαθούν έλεγχος αναφορά τέλειοι. Του την βιαστικά ρουτίνα ως όσο. Άρα προσεκτικά νιρβάνα βασανίζουν δίνοντας φακέλους ένα ακούσει.', 'Κανόνα με των χώρου μέχρι. Από έξι δε δούλευε. Αν χρησιμοποιούνταν φράση πολύ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('2', '3004006308', '0710672829');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('2', '688', '2016-05-13 00:00:00', '2016-05-15 00:00:00', 'Συνηθίζουν έστελνε κανένας εδώ οι ο γεύματος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('3', '1210498423', '0909929669');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('3', '14576', '2018-01-12 00:00:00', '2018-02-01 00:00:00', 'Προσοχή έτσι έχω πόρτες ένας απόλαυσε τα αναγκάζονται. Για της πολύ εξακολουθεί σε.', 'Δημιουργείς που με γειτονιάς. Κάτι άλγεβρα μέσης σχεδιαστής σπίτι οι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('4', '2605487804', '3107812169');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('4', '111712', '2005-07-02 00:00:00', '2005-07-04 00:00:00', 'Παίρνει γνωρίζουμε ξέχασε σκεφτείς ναι λίγο κοιτάζοντας. Μάτσο πιο λίγο οι σημεία ειδικά. Εργοστασίου έτσι θέμα τοπικές.', 'Ο αρχεία τι τεκμηριώνει ένας. Τα οι της πεδία ο πάρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('5', '1901834097', '0108825493');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('5', '14520', '2003-10-31 00:00:00', '2003-11-21 00:00:00', 'Με πόρτες χάος. Σημαντικό στις κώδικα επιστρέφουν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('6', '2808429905', '0712591524');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('6', '149125', '2020-04-05 00:00:00', '2020-05-19 00:00:00', 'Άρα απαράδεκτη τεσσαρών άλγεβρα μεταφραστής ατόμου προσλάμβανες. Νιρβάνα μεταφραστής ναι δεν πετάξαμε αφήσεις. Απομόνωση δυστυχώς γραμμής.', 'Νέου να μη τη ήδη. Σταματάς πες πάντως να μέχρι. Πως ένα υόρκη ερωτήσεις πάρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('7', '2601455764', '2803113618');
