INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('8', '3011473425', '0909929669');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '118023', '2002-06-08 00:00:00', '2002-07-06 00:00:00', 'Ανεπιθύμητη εξαρτάται μεταγλωτίσει των συγχρόνως οι.', 'Φίλος ποσοστό ιδιαίτερα των. Ακούσει έτοιμος κι.');
