INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('9', '37190', '2025-05-28 00:00:00', '2025-07-17 00:00:00', 'Τρόποι την πρώτο μέρος αγοράζοντας. Που σαν διαπιστώνεις στα τα ανά χαμηλός. Εργαζόμενων διαφήμιση πολύ μα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('10', '1603692480', '1807971230');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('10', '32436', '2007-07-13 00:00:00', '2007-08-19 00:00:00', 'Αρχεία όσο ένα αλγόριθμου βγήκε μάθε έχω. Την πως τις μην δίνοντας μην. Έτσι σημαντικός συνάδελφος μιας βγήκε ρωτήσει έλεγχος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('11', '1710567296', '1710918492');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '31498', '2007-12-07 00:00:00', '2007-12-10 00:00:00', 'Ναι ημέρα χαρακτηριστικών πετάξαμε. Εγώ κάτι ας εδώ σου είχαμε. Λιγότερο αυτήν υπηρεσία την μπορούσες χρονοδιαγράμματος δυστυχώς.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('12', '2312920992', '3003255946');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('12', '19597', '2002-07-17 00:00:00', '2002-09-03 00:00:00', 'Κανείς φίλος αναφέρονται. Ένα απαρατήρητο ανώδυνη στη δωροδοκηθούν. Εξοργιστικά γραμμές μου εργάστηκε μας.', 'Στις σημεία μην άτομο πιο ας κάνεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('13', '3101684544', '2109450705');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('13', '36779', '2020-08-10 00:00:00', '2020-09-02 00:00:00', 'Προσοχή ελέγχου λίγο υψηλότερη φακέλους διαχειριστής γεύματος αναφορά. Παράγοντες μου απλό νέο πάντως κειμένων εκθέσεις.', 'Δύο ανώδυνη μα απλό μηχανής αποδείξεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('14', '3004712447', '0306253198');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('14', '150948', '2013-06-29 00:00:00', '2013-08-16 00:00:00', 'Θέλεις μέσης νόμιζες ροή έχω μην.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('15', '3003792611', '0509468965');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('15', '32731', '2016-01-31 00:00:00', '2016-02-23 00:00:00', 'Παίξουν πετούν περιβάλλον θέματα ήδη με ήδη. Σταματάς αρπάζεις δεδομένων μα εδώ σαν θα. Τι ανταγωνιστής αφήσεις εφαρμογής ας συγχωνευτεί συγγραφής τις. Στις προκαλείς που πηγαίου χρησιμοποιούσες.', 'Κάτι ως αποδείξεις πάρα. Σας τους πετούν εδώ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('16', '2605487804', '0311667656');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('16', '78380', '2001-10-23 00:00:00', '2001-10-26 00:00:00', 'Τοπικές έξι κώδικα του θέματα. Συγκεντρωμένοι επιχείριση μέχρι ρουτίνα λετπά από παίξουν στις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('17', '2406702508', '0707511753');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('17', '85417', '2007-07-12 00:00:00', '2007-08-07 00:00:00', 'Δύο θέμα ρωτήσει προγραμματιστής. Θα τρόπο πάντως κι δεν ήδη. Διακόψουμε ιδιαίτερα έχω. Πάντως μάλλον παραπάνω κώδικα την από.', 'Παίξουν κάτι επιδιόρθωση τα. Διαδίκτυο απίστευτα μου αρχεία συγγραφείς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('18', '2002557930', '2205949174');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('18', '35711', '2008-04-07 00:00:00', '2008-05-01 00:00:00', 'Μιας κοιτάζοντας προγραμματιστής μια επί. Πάντα κρατήσουν συνεντεύξεις βγήκε. Λιγότερο λέει ναι αγοράζοντας.', 'Επί ένα πρώτοι ροή σκεφτείς. Εκείνου εκτελέσει έξι έρθει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('19', '3101684544', '0708685120');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('19', '63938', '2026-10-18 00:00:00', '2026-11-29 00:00:00', 'Γραμμή απόλαυσε έτσι ότι μπορούσες ας. Κρατάει επιστρέφουν παραγωγικής συγκεντρωμένοι τους σου.', 'Πετούν για ανεπιθύμητη σημεία. Πρώτο γεγονός συνεχώς επί το επενδυτής δίνοντας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('20', '3004006308', '0207523564');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('20', '92583', '2010-09-20 00:00:00', '2010-10-08 00:00:00', 'Σαν γραμμή εκτός με. Νέο και τρόπο έχω εγώ. Σημεία γέλασαν το ακούσει από λέει αυτός.', 'Ανά ίδιο ιδιαίτερα διάβασε. Κύκλο πάρεις στραβά υψηλότερη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('21', '2605487804', '1306400686');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('21', '64071', '2011-12-23 00:00:00', '2012-02-20 00:00:00', 'Μιας σημεία μη απόλαυσε εσωτερικών σπίτι. Φίλος εκείνου κι χρόνου στο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('22', '3003792611', '2403124298');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('22', '113781', '2013-02-15 00:00:00', '2013-03-03 00:00:00', 'Αρχεία αναφέρονται όταν ήδη. Χαρτιού άρα συγγραφής. Περίπου πάντως υποψήφιο γραφικά θυμάμαι σημεία ένας δεν.', 'Επιδιόρθωση διασφαλίζεται διευθυντές φαινόμενο πολύ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('23', '2504594248', '2208147233');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('23', '63782', '2009-08-13 00:00:00', '2009-09-04 00:00:00', 'Αποστηθίσει ελέγχου υπηρεσία χρειάζονται έστειλε εκτελείται. Μετράει θέμα τρόπο. Συνάδελφος τι δουλεύει μεταγλωτίσει δίνοντας χρονοδιαγράμματος.', 'Κλπ ας πάντα πες. Ορίστε κάτι το. Χειρότερα ποσοστό άτομο λαμβάνουν δείξει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('24', '3101684544', '2804244819');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('24', '108203', '2024-11-26 00:00:00', '2024-12-30 00:00:00', 'Στέλνοντάς μα πεδία απαραίτητο μέχρι συγγραφής προκαλείς. Κειμένων υπηρεσία από ζητήσεις. Βάζοντας παράγοντες πηγαίου εκτός στα εκδόσεις εκείνου.', 'Όσο διαπιστώνεις ανταγωνιστής. Δε λιγότερο χαρτιού προσεκτικά έτσι κάτι τύπου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('25', '0704753686', '0303734492');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('25', '120494', '2013-12-11 00:00:00', '2014-01-03 00:00:00', 'Δημιουργια δουλεύει ορίστε. Κώδικάς γνωρίζουμε όσο πλέον οι δημιουργήσεις ποια.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('26', '1303774169', '0810951315');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('26', '113746', '2004-08-16 00:00:00', '2004-10-13 00:00:00', 'Όσο αρέσει και σε χρονοδιαγράμματα πλέον. Προκύπτουν τεκμηριώνει στις νιρβάνα. Βιβλίο σημαντικό ερώτηση παραγωγικής γνωστή. Τεσσαρών άρα μην.', 'Μηχανής εδώ έστελνε. Ναι άρα κανένας μη έτοιμος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('27', '1108613101', '1009472948');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('27', '117877', '2014-07-02 00:00:00', '2014-08-17 00:00:00', 'Χρησιμοποιούσες μην εφαρμογής. Πολύ κόλπα διακοπή βάζοντας ένας μου. Όσο προσπαθήσεις πόρτες ανταγωνιστής σίγουρος.', 'Συγχωνευτεί εδώ δεν σημαντικός συνάδελφος βουτήξουν περιεχόμενα πακέτων.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('28', '2011502344', '2103241696');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('28', '26807', '2021-01-07 00:00:00', '2021-01-22 00:00:00', 'Ναι συνηθίζουν ναι πολύ αλγόριθμου εκείνου εξαρτάται. Αναγκάζονται παράγοντες μου καταλάθος ίδιο.', 'Πάντα δύο χαμηλός. Κρατήσουν αν διοικητικό προσπαθούν πλέον έτοιμος να.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('29', '0412557508', '2111097414');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '42691', '2003-02-02 00:00:00', '2003-02-22 00:00:00', 'Μου κανόνα ότι μάλλον συνεχώς. Ένας σωστά κώδικα γραμμής γεύματος ξέχασε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('30', '1207891405', '0108825493');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '144824', '2021-09-07 00:00:00', '2021-10-18 00:00:00', 'Και νόμιζες ως. Προσπαθήσεις διάβασε τις. Μπορούσες στις χαμηλός μηχανής γραφικά.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('31', '0504870342', '0605997909');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('31', '80730', '2013-11-13 00:00:00', '2014-01-06 00:00:00', 'Εκτός έτσι εκδόσεις προκαλείς. Παραγωγικής δύο γέλασαν διακόψουμε θέλεις απομόνωση. Ένας όχι ναι έξι μέχρι εργαλείων υποψήφιο.', 'Εκτελέσει έλεγχος δωροδοκηθούν ρωτάει φράση τελειώσει διορθώσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('32', '0701585507', '2103189200');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('32', '28159', '2008-03-23 00:00:00', '2008-04-11 00:00:00', 'Χάος ρωτάει πήρε εργοστασίου. Και την που κοιτάζοντας απίστευτα των προσθέσει. Πάντα χρησιμοποιώντας θέματα προσεκτικά αναγκάζονται συνέχεια.', 'Απαρατήρητο χρησιμοποιώντας αν πρώτης αρέσει. Ένα την από.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('33', '1503650145', '1711820259');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '101581', '2021-10-09 00:00:00', '2021-11-12 00:00:00', 'Αυτήν κι ποια έτσι χρονοδιαγράμματος. Συγχωνευτεί μεταγλωτιστής άτομο γνωστή ορίστε τύπους. Δείξει προκύπτουν πάντως εργαλείων ρουτίνα έχω.', 'Χάος παραδώσεις θέλεις αφήσεις γέλασαν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('34', '1210498423', '2102707225');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '34871', '2009-03-18 00:00:00', '2009-04-22 00:00:00', 'Διάβασε άλγεβρα έγραψες αρχεία παράγοντες στήλες δεν. Μου ας εργαλείων εγώ απίστευτα. Άρθρων γειτονιάς μέρος τον λέει. Στο μαγικά δε περίπου.', 'Πετούν τέλειοι πάντα δοκιμάσεις τα γραμμή ότι ίδιο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('35', '1710672160', '2810172600');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('35', '128400', '2015-08-03 00:00:00', '2015-09-20 00:00:00', 'Αν ιδιαίτερα κάνε που χαμηλός ας. Δυστυχώς σχεδιαστής δύο συγκεντρωμένοι παίξουν. Πρώτης ήδη υπηρεσία του πάντα μεταγλωτιστής ανακλύψεις.', 'Σκεφτείς της χαρακτηριστικό διαχειριστής. Διαδίκτυο μου γειτονιάς αυτός.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('36', '1803665740', '0206102410');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('36', '141212', '2018-06-04 00:00:00', '2018-07-24 00:00:00', 'Κι γραφικά είχαμε μη. Συνεχώς καλύτερο τι ανεπιθύμητη γεγονός πλέον σπίτι διευθυντές.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('37', '1210403337', '2803145534');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('37', '66573', '2015-01-22 00:00:00', '2015-03-15 00:00:00', 'Μετρήσεις σίγουρος πάντα άρα ας. Ας πρόσληψη κρατάει περιμένουν μέχρι επί λες.', 'Το μέγιστη μεταφραστής απόλαυσε έτοιμος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('38', '1801548897', '0709659298');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('38', '137476', '2018-08-02 00:00:00', '2018-09-16 00:00:00', 'Σε κώδικα σημαντικός του περιεχόμενα. Δύο πιο διορθώσει έχω έχω. Αφήσεις τεσσαρών επί τεκμηριώνει σχεδιαστής πρώτοι.', 'Δε έχω διασφαλίζεται χρόνου πιο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('39', '1210498423', '1902872336');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('39', '4724', '2016-04-07 00:00:00', '2016-05-10 00:00:00', 'Πάντως των ας τι. Προσπαθήσεις προγραμματιστής επενδυτής χρονοδιαγράμματα χρησιμοποιούσες.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('40', '2107914588', '2602192188');
