INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('41', '2406702508', '2205799942');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('41', '42085', '2025-08-01 00:00:00', '2025-09-22 00:00:00', 'Το φίλος πρόσληψη άρα νέα τη που. Ήδη σε δε βουτήξουν συνέχεια δεν. Αναφέρονται απαρατήρητο προγραμματιστής δύο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('42', '3011473425', '2103241696');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('42', '94480', '2013-05-10 00:00:00', '2013-07-09 00:00:00', 'Φίλος πολύ εξαρτάται επενδυτής χειρότερα προϊόντα έχω. Τρόπο χρησιμοποιούνταν εκδόσεις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('43', '0308605311', '1103649074');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('43', '67300', '2015-08-24 00:00:00', '2015-10-16 00:00:00', 'Μετράει τεκμηριώνει νιρβάνα στα εγώ σαν της. Πάρα χαμηλός ερώτηση πλέον. Συνάδελφος αντιλήφθηκαν άτομο ανά.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('44', '0406917233', '1909034370');
