INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('45', '3004006308', '1107727831');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('45', '26320', '2020-03-27 00:00:00', '2020-05-14 00:00:00', 'Μας γεγονός έγραψες τους εργαζόμενοι. Απομόνωση τεσσαρών σημαντικός εφαμοργής. Δίνοντας εφαμοργής μην πάντως κι βιαστικά.', 'Για αν των υψηλότερη μας στήλες μου μέχρι.');
