INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('47', '3003792611', '0511007549');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('47', '27744', '2024-11-30 00:00:00', '2025-01-29 00:00:00', 'Λες περίπου δεδομένων όχι. Ανά συγκεντρωμένοι στο ώρα ο αναφέρονται.
