INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('48', '9465', '2007-12-19 00:00:00', '2008-01-06 00:00:00', 'Πάντα γραφικά βάζοντας την παράγοντες δύο. Πάντως καλύτερο επιστρέφουν ζητήσεις κώδικάς την ερωτήσεις αρπάζεις.', 'Πολύ επεξεργασία κάνεις δούλευε ανά του σε. Βιαστικά μετρήσεις πρώτο ατόμου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('49', '0804835842', '2909783680');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('49', '76567', '2001-09-27 00:00:00', '2001-10-02 00:00:00', 'Μπουν κανένας ίδιο προγραμματιστές στις παίξουν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('50', '3004006308', '2207135019');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('50', '40350', '2010-02-18 00:00:00', '2010-02-27 00:00:00', 'Πλέον τους διάσημα έρθει περιεχόμενα παίξουν υψηλότερη ρωτάει. Ακούσει αναφέρονται νέου. Έστελνε στραβά πρώτης εντολές ήδη δημιουργείς.', 'Βασανίζουν σημαντικός προκύπτουν επιχείριση. Πάρα τα κώδικάς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('51', '2605487804', '2608651365');
