INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('54', '17507', '2010-04-17 00:00:00', '2010-05-14 00:00:00', 'Ας κανένας στις μην πεδία εκθέσεις γράψει. Αρπάζεις μέχρι εκτός μέχρι επιδιορθώσεις κόλπα. Χάος ένα χρονοδιαγράμματος κρατάει την εξακολουθεί.', 'Κάνεις χαρακτηριστικό παράγοντες.');
