INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('55', '38597', '2008-01-02 00:00:00', '2008-02-13 00:00:00', 'Ερώτηση τρόποι ροή εξαρτάται τις. Εξοργιστικά μην περίπου επιστρέφουν. Σας νέο συνεχώς χρειάζονται πλέον κάτι δύο.', 'Χαρτιού άρθρων κάτι πάντα ατόμου πλέον.');
