INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('97', '35924', '2009-12-29 00:00:00', '2010-02-17 00:00:00', 'Επενδυτής απαρατήρητο όσο χρησιμοποιούνταν λοιπόν. Εξακολουθεί γραφικά μα έστελνε βαθμό.', 'Πήρε τα για κι εκτός κόλπα υπηρεσία. Εταιρείες εφαρμογής διολισθήσεις πως.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('98', '2009883975', '1109577348');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('98', '116981', '2018-05-24 00:00:00', '2018-07-01 00:00:00', 'Καταλάθος πλέον εφαρμογή τελειώσει άτομο διασφαλίζεται κάνεις. Γειτονιάς δυστυχής εγώ συνεχώς μας δωροδοκηθούν διαπιστώνεις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('99', '1108564422', '1309964980');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('99', '128857', '2025-07-05 00:00:00', '2025-07-23 00:00:00', 'Χαμηλός χάος πετάνε δε. Περισσότερες αυτός προκύπτουν ευκολότερο σταματάς επί. Χαμηλός νέων δούλευε πιο.', 'Τοπικές πως προκαλείς ποσοστό μην περιμένουν. Παραπάνω πάντως χρησιμοποιούνταν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('100', '1207891405', '2008769961');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('100', '89777', '2012-03-10 00:00:00', '2012-05-01 00:00:00', 'Εικόνες ρουτίνα παράγοντες γεύματος εργασίας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('101', '1710672160', '1505817410');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('101', '89657', '2002-02-12 00:00:00', '2002-03-19 00:00:00', 'Έτσι διακοπή διευθυντές ρωτάει πεδία. Ας λιγότερο ας έρθει από γεγονός. Έγραψες παραδώσεις κανένας των από καταλάθος. Αντιλήφθηκαν τοπικές στη σταματάς γράψει στα ήδη μάλλον.', 'Λέει κόλπα παράδειγμα έξι ιδιαίτερα υπηρεσία χαρακτηριστικών.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('102', '0511424115', '3110857444');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('102', '55903', '2001-12-11 00:00:00', '2002-01-27 00:00:00', 'Πάρεις συγχρόνως γραφικά κανόνα ότι προσθέσει υπηρεσία. Τεσσαρών επενδυτής ώρα έξι πρώτο. Μου αποστηθίσει δημιουργια επιχείριση μου μέγιστη πρώτοι δωροδοκηθούν.', 'Από αρχεία αρέσει δούλευε. Όχι διολισθήσεις καλύτερο δε. Μας την κάτι ίδιο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('103', '2504923050', '0903571549');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '71022', '2002-05-24 00:00:00', '2002-06-27 00:00:00', 'Πετάξαμε σταματάς εκτός χώρου λαμβάνουν με τους. Τη έτσι στο ποσοστό εφαμοργής της πάντα. Για κι μου του. Ελέγχου χρονοδιαγράμματα τον αναγκάζονται ξέχασε προβληματική.', 'Του μέχρι μη εδώ της φίλος. Απαραίτητο πολύ μάτσο αν επενδυτής σημεία μάθε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('104', '0210528071', '2411748854');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('104', '148586', '2026-08-15 00:00:00', '2026-09-06 00:00:00', 'Μια τελειώσει δίνοντας μετράει. Δούλευε απλό μεταφραστής τα βασανίζουν καλύτερο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('105', '1103582631', '0510809788');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('105', '52020', '2020-02-07 00:00:00', '2020-03-31 00:00:00', 'Χάος πετάνε ο τον συγγραφής. Παραδώσεις δε παραγωγικής ροή θέλεις απαραίτητο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('106', '2906918313', '2004635881');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('106', '37304', '2018-01-29 00:00:00', '2018-03-23 00:00:00', 'Γέλασαν μάλλον μα αφήσεις κάνεις δούλευε. Αρέσει χαρακτηριστικών κρατάει λες στις. Άρα εδώ γνωστή ερωτήσεις δε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('107', '0509904221', '1405875645');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('107', '74688', '2007-01-12 00:00:00', '2007-02-04 00:00:00', 'Την προβληματική χρειάζονται μετρήσεις ανεπιθύμητη μέγιστη οι. Πάρα βιαστικά στο λαμβάνουν γνωστή ξέχασε.', 'Επί μέχρι γιαυτό εδώ επιχείριση μας δωροδοκηθούν. Γραφικά δεν δούλευε σίγουρος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('108', '0509904221', '0102741559');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('108', '112467', '2019-11-20 00:00:00', '2020-01-06 00:00:00', 'Διαφήμιση γραμμή αν αναγκάζονται. Ήδη τρέξει στέλνοντάς δημιουργήσεις. Θέλεις για απαράδεκτη μερικούς χρησιμοποίησέ.', 'Ένα γραμμής ας μεταφραστής. Εγώ προκύπτουν για εκτελέσεις απίστευτα της κύκλο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('109', '2002557930', '0407012581');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('109', '101715', '2007-01-29 00:00:00', '2007-02-26 00:00:00', 'Παραδώσεις χρησιμοποιούσες πιο βάζοντας. Στα αθόρυβες σίγουρος εκτελείται έτσι. Πάντως πάντως νόμιζες παραδοτέου χρονοδιαγράμματα σου κοιτάζοντας.', 'Περισσότερες καταλάθος διολισθήσεις έχω αρέσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('110', '2206905349', '0409610284');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('110', '21718', '2019-07-06 00:00:00', '2019-07-18 00:00:00', 'Προϊόντα σημαντικό επεξεργασία για. Βαθμό γραμμή πολύ έγραψες μην. Προγραμματιστής ποσοστό εδώ μεταφραστής έτσι.', 'Γειτονιάς μα των δυστυχώς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('111', '1603973073', '2611668702');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('111', '118125', '2026-09-07 00:00:00', '2026-09-26 00:00:00', 'Αποστηθίσει του κι βιαστικά. Στις παράγοντες κώδικάς σαν ποσοστό γράψει. Διαδίκτυο κι κάτι.', 'Μα ξέχασε ερωτήσεις. Χάος τι προβληματική συγκεντρωμένοι ένας διακοπής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('112', '0411000633', '2807865321');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('112', '156893', '2024-04-07 00:00:00', '2024-04-16 00:00:00', 'Έξι περίπου αν πηγαίου διαδίκτυο επεξεργασία χρονοδιαγράμματα. Αναγκάζονται τρέξει συγγραφής πολύ. Ειδικά εργάστηκε πως ιδιαίτερα.', 'Συγγραφής κόλπα διοικητικό μέχρι. Ζητήσεις εξακολουθεί έξι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('113', '1309544067', '0605997909');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '111966', '2022-08-16 00:00:00', '2022-10-05 00:00:00', 'Ρουτίνα πρόσληψη πιο προϊόντα κι. Μας σας λίγο έλεγχος ροή απίστευτα κάνε. Μέχρι έλεγχος κόλπα μάτσο μπουν εδώ και.', 'Ανά αντιλήφθηκαν ημέρα εκτελείται. Κόψεις όσο αν τους.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('114', '3008569879', '0903571549');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('114', '94468', '2019-05-07 00:00:00', '2019-05-26 00:00:00', 'Τρόποι έτσι συγγραφής διευθυντές. Δύο ωραίο απαράδεκτη έχω γραφικά την.', 'Συνέχεια διορθώσει διακοπής τύπου σίγουρος μηχανής διορθώσει προσπαθήσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('115', '3008569879', '2311860823');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '68930', '2025-04-24 00:00:00', '2025-06-03 00:00:00', 'Απαραίτητο συνάδελφος σχεδιαστής βιβλίο ναι διακοπής. Για κώδικα ως τρόπο λιγότερο παίρνουν εργαζόμενοι. Φίλος τεκμηριώνει όσο πάντως νέων.', 'Εικόνες τα μετράει δημιουργείς λιγότερο. Πως υψηλότερη πιο ζητήσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('116', '0509904221', '3110857444');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('116', '114070', '2021-02-17 00:00:00', '2021-04-15 00:00:00', 'Στις υόρκη πόρτες προκύπτουν κανείς. Ας δημιουργήσεις γιαυτό υποψήφιο. Την γεγονός κάτι αρχεία.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('117', '0509904221', '2402780036');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('117', '77706', '2002-11-03 00:00:00', '2002-12-14 00:00:00', 'Βαθμό κανένας άτομο υποψήφιο. Κάτι διακοπή πιο προσλάμβανες μας. Ρωτάει συγχρόνως σκεφτείς πως σωστά εκτελέσει.', 'Ατόμου πάντως μας χαρακτηριστικό όσο του ως ποσοστό.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('118', '2011502344', '1309931230');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('118', '96743', '2023-09-17 00:00:00', '2023-11-15 00:00:00', 'Πρώτο ειδικά πάντα χρησιμοποιούνταν. Ίδιο εταιρείες κι τέλειοι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('119', '0406917233', '1107727831');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('119', '46410', '2017-11-06 00:00:00', '2017-11-17 00:00:00', 'Ναι πιο λες κοιτάζοντας ώρα παραδοτέου. Ανταγωνιστής κάνε τους παίξουν συγγραφής.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('120', '1503650145', '2309635025');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('120', '97434', '2007-10-07 00:00:00', '2007-11-13 00:00:00', 'Κι λετπά σωστά ας προγραμματιστές. Εκείνου εδώ σημαντικός ανά αποθηκευτικού αναγκάζονται απαράδεκτη.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('121', '3008569879', '0903784828');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('121', '135487', '2020-08-26 00:00:00', '2020-09-16 00:00:00', 'Όταν απίστευτα αρχεία κώδικα τρόποι ένας εφαρμογής. Τη τέλειοι προγραμματιστής στο εργαζόμενων.', 'Και μάθε εργαζόμενοι των μετρήσεις λετπά. Τα σκεφτείς γράψει δείξει του.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('122', '1704959308', '1909034370');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('122', '119552', '2004-02-29 00:00:00', '2004-04-03 00:00:00', 'Απόλαυσε μας γραμμής χαμηλός ώρα τους. Αναφορά έλεγχος γέλασαν πως εντολές πόρτες. Φίλος μη γράψει ένας πετούν εικόνες.', 'Κειμένων ο στα επιδιόρθωση επιστρέφουν κύκλο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('123', '3101684544', '0712591524');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '159586', '2005-05-28 00:00:00', '2005-06-13 00:00:00', 'Την μου ήδη παράγοντες ανεπιθύμητη υποψήφιο περιμένουν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('124', '1708456505', '0701237120');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('124', '29607', '2021-05-31 00:00:00', '2021-07-09 00:00:00', 'Κανείς σχεδιαστής της πάρεις ο έτσι εγώ. Προσπαθούν δίνοντας εργαλείων έστελνε δε προσπαθήσεις. Φίλος μου δεδομένων ανά παραπάνω ανά πλέον.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('125', '1801548897', '0810951315');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '14284', '2021-09-26 00:00:00', '2021-11-08 00:00:00', 'Εκτός σταματάς επιδιόρθωση αρπάζεις. Θα ένας μέχρι ερωτήσεις χρησιμοποίησέ επεξεργασία ξέχασε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('126', '2906009791', '1408446826');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('126', '41653', '2017-07-25 00:00:00', '2017-09-02 00:00:00', 'Πολύ άτομο περιβάλλοντος συγχρόνως. Δυστυχώς βρίσκονται καταλάθος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('127', '2708902048', '0409610284');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('127', '28562', '2019-05-05 00:00:00', '2019-06-22 00:00:00', 'Άλγεβρα άρα συνέχεια τρόπο έτοιμος το. Σας έτσι είχαμε πάντως. Εργαζόμενοι κι γειτονιάς μπουν από λαμβάνουν τύπους.', 'Μου λετπά μετράει στο διορθώσει δεν. Ήδη ακούσει όχι κανένας ημέρα δύο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('128', '2901915784', '1309931230');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('128', '69832', '2005-01-06 00:00:00', '2005-02-14 00:00:00', 'Δύο τα αρέσει άλγεβρα άπειρα. Λιγότερο και έτσι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('129', '1603692480', '0509468965');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('129', '106413', '2011-03-15 00:00:00', '2011-05-03 00:00:00', 'Αυτός να γιαυτό ανεπιθύμητη γραμμή. Τύπου ότι χρησιμοποιούσες παράδειγμα χαμηλός έστειλε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('130', '2011458949', '2607536626');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('130', '120625', '2019-02-22 00:00:00', '2019-03-08 00:00:00', 'Και προσλάμβανες πετούν γράψει.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('131', '3010528248', '0510809788');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('131', '71295', '2022-03-19 00:00:00', '2022-04-15 00:00:00', 'Εκτελέσεις φράση σχεδιαστής εργοστασίου μέγιστη επί γραμμή. Και διαφήμιση παίξουν τρόποι διαφήμιση μέσης κάτι μου. Μέχρι έστελνε γνωρίζουμε έγραψες. Ανεπιθύμητη διαπιστώνεις των χρονοδιαγράμματα.', 'Μας ναι κανένας διορθώσεις κι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('132', '2204727653', '3003169109');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('132', '73028', '2006-03-30 00:00:00', '2006-05-23 00:00:00', 'Γραμμή βρίσκονται αυτός σου. Δίνοντας κόλπα απαρατήρητο αναφέρονται πάντα σχεδιαστής. Ας αυτός ρουτίνα απλό γειτονιάς διάβασε των.', 'Πάντως εκτελέσει έτσι όσο σε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('133', '1708456505', '0509970265');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('133', '74286', '2019-05-22 00:00:00', '2019-06-19 00:00:00', 'Αποστηθίσει προϊόντα πετάνε λετπά γέλασαν νέων. Λες ποια πως μετρήσεις εδώ. Ζητήσεις εντολές μην ερωτήσεις κι άρθρων.', 'Κώδικάς μπορούσες τύπου γεγονός κρατήσουν αφήσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('134', '1710567296', '1402892299');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('134', '10352', '2002-09-12 00:00:00', '2002-10-19 00:00:00', 'Όσο φίλος προκύπτουν βάζοντας ναι της. Ευκολότερο πάντως πηγαίου γιαυτό εφαρμογή δημιουργήσεις σε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('135', '1710672160', '2804244819');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('135', '38967', '2009-09-28 00:00:00', '2009-10-16 00:00:00', 'Γεγονός παίρνουν διασφαλίζεται μέχρι. Κλπ στα προσπαθούν προβληματική ύψος δημιουργείς εξακολουθεί. Εκθέσεις αναφορά απομόνωση παίρνει. Πάρα παίρνει υόρκη κύκλο συνεχώς βουτήξουν αρχεία.', 'Εφαρμογής νέα ήδη εγώ έστελνε της. Κώδικάς σίγουρος τελειώσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('136', '0308605311', '0902070949');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('136', '108161', '2013-03-30 00:00:00', '2013-04-11 00:00:00', 'Και χρονοδιαγράμματα χαμηλός. Τρέξει για ας εργαζόμενοι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('137', '1603692480', '0909929669');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '53347', '2005-04-08 00:00:00', '2005-05-13 00:00:00', 'Χρόνου συγγραφής ένας μεταγλωτίσει κι. Ο ύψος ξέχασε αν. Μεταφραστής μπορούσες ένα αρέσει πάντα αυτήν ίδιο πως. Που μερικούς έτοιμος ωραίο προγραμματιστής χρησιμοποιούσες πάρα.', 'Γνωστή εξαρτάται πως αθόρυβες τρέξει δεν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('138', '0412557508', '2205949174');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('138', '108814', '2006-09-15 00:00:00', '2006-09-26 00:00:00', 'Του αφήσεις νόμιζες επιστρέφουν την αγοράζοντας διαπιστώνεις. Υποψήφιο συνεχώς εξακολουθεί για όταν εγώ ο. Γεγονός δοκιμάσεις με ανεπιθύμητη τι σημεία.', 'Ερώτηση μέγιστη διακοπής για είχαμε. Εκτός υποψήφιο δύο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('139', '2206905349', '0510809788');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('139', '27724', '2000-09-25 00:00:00', '2000-10-31 00:00:00', 'Εκτελέσει προσπαθούν το τα διάσημα δουλεύει χειρότερα. Συνεχώς υψηλότερη ήδη περιεχόμενα. Καταλάθος ότι περιβάλλον δημιουργείς πλέον.', 'Που κανόνα αποκλειστικούς κι μη κι μέγιστη. Αυτήν πετάξαμε επί.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('140', '2701528412', '3003255946');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('140', '155096', '2016-06-26 00:00:00', '2016-06-28 00:00:00', 'Νιρβάνα ο θυμάμαι επί μου γνωρίζουμε. Εκτελείται χώρου δύο στις γνωρίζουμε. Μάλλον πάρα σας αποκλειστικούς πάντα. Κόψεις αποδείξεις με νέων ανταγωνιστής εκδόσεις εργασίας.', 'Φακέλους επί βουτήξουν δίνοντας. Μέχρι στη διασφαλίζεται έτσι εργαζόμενων.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('141', '0109785464', '0212961683');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('141', '30105', '2001-12-26 00:00:00', '2002-02-22 00:00:00', 'Νέων πάντα ξέχασε δεδομένων. Πλέον υόρκη δύο έστειλε φράση όταν χρησιμοποιούσες. Έξι τρέξει δυστυχής βιαστικά διαπιστώνεις γνωρίζουμε υψηλότερη φράση. Σας ανά λετπά κάνεις μέχρι από επί του.', 'Άρα θα όχι ήδη προσλάμβανες απαραίτητο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('142', '1901834097', '2702939519');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('142', '133857', '2003-10-27 00:00:00', '2003-11-29 00:00:00', 'Εκθέσεις κάνε ημέρα δύο καταλάθος ότι στήλες τοπικές. Λαμβάνουν αποδείξεις στέλνοντάς διακόψουμε δίνοντας βουτήξουν προσλάμβανες.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('143', '0511424115', '0505546388');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('143', '34688', '2007-03-12 00:00:00', '2007-03-23 00:00:00', 'Εκθέσεις διασφαλίζεται περισσότερη εντολές τρόπο νέο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('144', '2605487804', '0602483460');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('144', '86054', '2025-05-27 00:00:00', '2025-07-03 00:00:00', 'Πολύ για λοιπόν νέο από δυστυχώς. Από μεταγλωτιστής διευθυντές. Ευκολότερο νιρβάνα προσλάμβανες έξι φακέλους συγγραφείς ανεπιθύμητη.', 'Εκείνου εκτός διολισθήσεις άλγεβρα περιβάλλοντος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('145', '1207891405', '2007023515');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('145', '39823', '2019-03-01 00:00:00', '2019-04-19 00:00:00', 'Κώδικα από σου κι περιβάλλοντος συγγραφής έγραψες. Ρωτάει προϊόντα προσοχή κώδικα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('146', '0305769634', '3003255946');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('146', '90661', '2007-11-24 00:00:00', '2008-01-18 00:00:00', 'Σε άτομο δύο αυτός κλπ υόρκη ένα στα. Ποσοστό πήρε δύο ίδιο με γεύματος όσο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('147', '0308605311', '2904413108');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('147', '131110', '2004-09-09 00:00:00', '2004-10-03 00:00:00', 'Ας πιο εξοργιστικά αρπάζεις. Σας ένας άρα περισσότερες κι γραμμής τον τα. Στο πολύ πολύ γραφικά κόλπα. Από γραμμή γραφικά χρονοδιαγράμματος πάντα μεταφραστής διοικητικό δημιουργήσεις.', 'Βιβλίο μερικούς προκύπτουν παίρνουν τι. Μου παίρνει για έξι δε την και.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('148', '2512659869', '0206102410');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('148', '145729', '2013-04-22 00:00:00', '2013-06-20 00:00:00', 'Κλπ από παράδειγμα εκτελέσεις φίλος εδώ. Ίδιο γραμμές να συνάδελφος όσο υψηλότερη κι διάσημα. Σαν στραβά γεγονός. Άρα προσθέσει χρονοδιαγράμματα τι.', 'Χειρότερα αποφάσισε εγώ ώρα υπηρεσία επιδιορθώσεις μαγικά ποια.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('149', '1212501178', '0911049527');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('149', '135067', '2015-06-14 00:00:00', '2015-07-20 00:00:00', 'Απομόνωση έξι θέμα επεξεργασία βασανίζουν στέλνοντάς. Επί φακέλους χαμηλός ανταγωνιστής φράση ανταγωνιστής επί εργαλείων.', 'Περισσότερη στο μπουν ανεπιθύμητη εκτελέσεις εικόνες εδώ ναι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('150', '1210498423', '2606881671');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('150', '123212', '2025-06-05 00:00:00', '2025-08-03 00:00:00', 'Δυστυχώς ατόμου επί δεν ατόμου συγχρόνως ας. Για θα έχω δουλεύει όχι γνωστή. Διακόψουμε επιστρέφουν ως πετούν αυτήν νέα δε δύο.', 'Μιας βουτήξουν για άπειρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('151', '2803927096', '0610662910');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('151', '9776', '2005-04-23 00:00:00', '2005-04-25 00:00:00', 'Εξακολουθεί ένα συνηθίζουν διακόψουμε γραμμές ένα πετούν κάτι. Χρονοδιαγράμματος παραπάνω πως σου.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('152', '2002557930', '2901672412');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('152', '64928', '2018-12-16 00:00:00', '2019-01-17 00:00:00', 'Πετάξαμε κοιτάζοντας θα τα τη των γεγονός. Πιο ίδιο εσωτερικών προσθέσει πάντως. Συγγραφείς πως ας εταιρείες δύο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('153', '2011458949', '1405875645');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('153', '34404', '2009-08-12 00:00:00', '2009-09-06 00:00:00', 'Απαράδεκτη μην χαρακτηριστικών τον πετάνε. Έτσι πλέον στις πάντα διαπιστώνεις μέχρι. Εργαλείων με περιβάλλοντος διακοπή έστειλε ρωτήσει.', 'Δημιουργια ο παραδώσεις. Ανταγωνιστής επιδιορθώσεις δεν επιστρέφουν δε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('154', '0411000633', '0810951315');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('154', '75055', '2023-02-04 00:00:00', '2023-03-05 00:00:00', 'Υποψήφιο πλέον πρώτο εφαρμογή. Εκτελείται πρώτο θέμα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('155', '1708456505', '0207523564');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('155', '6416', '2023-04-12 00:00:00', '2023-05-08 00:00:00', 'Να διοικητικό ανώδυνη αποκλειστικούς χάος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('156', '0406917233', '2608651365');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('156', '21713', '2014-06-19 00:00:00', '2014-07-20 00:00:00', 'Συνηθίζουν ότι διακοπή εκτελέσει. Αθόρυβες στραβά εξακολουθεί προσλάμβανες. Έγραψες ο δεν παραγωγικής λίγο.', 'Χαρτιού τον αυτός χρησιμοποιώντας και γραμμή εφαμοργής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('157', '1103582631', '0506746432');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('157', '17309', '2021-11-21 00:00:00', '2022-01-03 00:00:00', 'Ξέχασε προσοχή έτσι εικόνες ώρα σαν μετράει. Εδώ προγραμματιστές κάνε αφήσεις. Λέει εικόνες επιστρέφουν απόλαυσε.', 'Πρόσληψη νέου τον συγγραφής έχω πρώτο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('158', '0609801977', '0511007549');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('158', '143265', '2016-12-29 00:00:00', '2017-01-04 00:00:00', 'Με δουλεύει τέλειοι απαράδεκτη ο κι όταν μάλλον. Δύο αποδείξεις ανώδυνη προσπαθήσεις. Πάντα τρόποι στο το επιστρέφουν περισσότερη μεταφραστής.', 'Ζητήσεις χειρότερα προσπαθήσεις στη που τα. Καταλάθος ροή δεν άπειρα δύο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('159', '1210403337', '2704854969');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('159', '138680', '2007-05-04 00:00:00', '2007-06-07 00:00:00', 'Της ορίστε γνωστή νέα πως παίρνει. Έγραψες τους τα δημιουργήσεις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('160', '1901834097', '2007023515');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('160', '160834', '2005-10-25 00:00:00', '2005-11-13 00:00:00', 'Έτσι σας χρονοδιαγράμματος ας επεξεργασία ίδιο. Τους χρειάζονται των κύκλο σωστά ανακλύψεις μπουν. Υόρκη διακόψουμε ρωτάει επιδιόρθωση.', 'Ανά ένας συγγραφής δίνοντας σε αποστηθίσει εξαρτάται.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('161', '1801548897', '0502746763');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('161', '18856', '2016-07-02 00:00:00', '2016-07-09 00:00:00', 'Υψηλότερη τα άλγεβρα λετπά πιο πακέτων να έτσι. Συνηθίζουν εκτελέσει γιαυτό εκτελείται συνηθίζουν. Κώδικα επιδιόρθωση χρόνου γράψει σταματάς από.', 'Ιδιαίτερα στις επί μετρήσεις υπηρεσία όσο εκτός.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('162', '0701585507', '0109004072');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('162', '131836', '2014-05-30 00:00:00', '2014-06-11 00:00:00', 'Εκτελείται έρθει τέλειοι της τα. Και πάντα λαμβάνουν. Ξέχασε ζητήσεις συνάδελφος δεδομένων μιας.', 'Πάντως ποια τελειώσει χρειάζονται γειτονιάς σταματάς μέχρι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('163', '1309544067', '2602249843');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('163', '105738', '2005-10-04 00:00:00', '2005-10-05 00:00:00', 'Θέματα ότι του τρόπο. Αναφορά διάσημα άρα διευθυντές γραμμή μην έλεγχος πεδία. Εφαρμογή πακέτων εγώ δεν μέχρι πεδία.', 'Ναι γραμμής τη βγήκε προσοχή πιο. Εγώ πάντως διακοπή μια λέει δε προσθέσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('164', '0305769634', '3003169109');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('164', '151451', '2025-04-10 00:00:00', '2025-05-25 00:00:00', 'Γεγονός μετράει αθόρυβες γειτονιάς άρθρων γειτονιάς διοικητικό. Όσο αυτήν υόρκη σίγουρος ιδιαίτερα φακέλους. Έγραψες φράση σε τον.', 'Βρίσκονται εργάστηκε γραμμή. Παράγοντες ανά πάντα απαραίτητο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('165', '3008569879', '2312696135');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('165', '128676', '2014-10-17 00:00:00', '2014-11-16 00:00:00', 'Πιο νιρβάνα εφαρμογή πρόσληψη μαγικά εκθέσεις έρθει. Απλό θέμα ένας κάνε σωστά πακέτων.', 'Εντολές προγραμματιστής αν ζητήσεις διορθώσει απαρατήρητο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('166', '2605487804', '0408168793');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('166', '114973', '2006-11-13 00:00:00', '2007-01-09 00:00:00', 'Πηγαίου θέμα πάρα επιδιόρθωση εργασίας μπορούσες ορίστε. Δεν πετούν ανά εξακολουθεί ποια. Τις γειτονιάς τις από.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('167', '0202850965', '2103189200');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('167', '71810', '2009-04-21 00:00:00', '2009-05-23 00:00:00', 'Σε τεκμηριώνει σκεφτείς. Αυτός χαμηλός παραδοτέου βασανίζουν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('168', '2901915784', '2904413108');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('168', '155775', '2004-01-17 00:00:00', '2004-02-14 00:00:00', 'Εδώ ρωτάει όσο κάτι της. Χαμηλός απομόνωση γιαυτό πιο αποθηκευτικού νόμιζες. Των λέει μετράει απόλαυσε ήδη πετάξαμε πολύ χαρακτηριστικό.', 'Εγώ διαπιστώνεις κάνεις εκείνου επί. Φαινόμενο ήδη όσο λοιπόν πρώτο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('169', '0210528071', '3001250458');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('169', '143888', '2004-08-21 00:00:00', '2004-09-16 00:00:00', 'Χρησιμοποιώντας κοιτάζοντας σκεφτείς εκτός χαρακτηριστικό. Μας φράση λέει ένας. Οι αποθηκευτικού για απαραίτητο ειδικά στα περίπου.', 'Της συνηθίζουν πιο ένα καταλάθος διαδίκτυο. Ειδικά πάντα περισσότερη λες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('170', '1708456505', '2810245025');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('170', '10173', '2021-03-05 00:00:00', '2021-03-28 00:00:00', 'Πάντως μετρήσεις λιγότερο τύπους ο πιο. Χρησιμοποίησέ προϊόντα για πιο. Έξι τεσσαρών συνέχεια. Πάρα πεδία σου ευκολότερο μια.', 'Ναι υπηρεσία ελέγχου δύο ανεπιθύμητη γέλασαν παραπάνω.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('171', '2406702508', '2109450705');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('171', '25409', '2003-09-19 00:00:00', '2003-10-31 00:00:00', 'Πάντως δύο βιβλίο τρόπο. Πάντως απόλαυσε μεταφραστής.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('172', '1303774169', '1210967616');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('172', '90526', '2011-07-06 00:00:00', '2011-08-05 00:00:00', 'Έτσι εδώ ανά. Έτσι θέματα των μαγικά τις. Τρόποι χρησιμοποίησέ έχω μέρος πάρεις ροή.', 'Σας παράδειγμα αναφέρονται από στο ζητήσεις ως. Αναγκάζονται είχαμε πάντως.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('173', '2708902048', '1803831080');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('173', '68244', '2024-02-08 00:00:00', '2024-03-17 00:00:00', 'Πιο βάζοντας ποια απόλαυσε. Πρώτοι μπουν ως ως.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('174', '0202717529', '2907484293');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('174', '32843', '2002-12-03 00:00:00', '2003-01-27 00:00:00', 'Κάτι κι εντολές γραμμή. Τελειώσει πλέον στις θέματα αναγκάζονται ερώτηση. Κοιτάζοντας στο πάρα κάτι εδώ.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('175', '0712498524', '0511007549');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('175', '123567', '2004-07-05 00:00:00', '2004-08-28 00:00:00', 'Μεταγλωτιστής κώδικα ναι κι αν δε εφαρμογής. Των περίπου εγώ εκτελείται επιστρέφουν διάβασε ανώδυνη.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('176', '1210498423', '0102741559');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('176', '151677', '2016-03-07 00:00:00', '2016-03-10 00:00:00', 'Πάντα ιδιαίτερα παίρνει γραμμές ελέγχου βρίσκονται. Στέλνοντάς πιο κώδικα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('177', '1303774169', '2210041375');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('177', '156870', '2018-11-24 00:00:00', '2019-01-09 00:00:00', 'Επί ρωτάει τύπου.
