INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('178', '62176', '2009-07-08 00:00:00', '2009-09-01 00:00:00', 'Εργαλείων άπειρα εκτελέσει στα. Την ροή εγώ σίγουρος τα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('179', '2406702508', '0610662910');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('179', '84678', '2010-10-29 00:00:00', '2010-11-07 00:00:00', 'Σαν στις μέχρι χρονοδιαγράμματος νέου. Αρέσει μας ζητήσεις ότι χρησιμοποιούσες χρησιμοποίησέ εφαρμογής έχω. Του πολύ έχω συγχρόνως.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('180', '3004712447', '2811467326');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('180', '67071', '2026-03-17 00:00:00', '2026-04-04 00:00:00', 'Προκαλείς υόρκη αγοράζοντας εφαμοργής πόρτες. Γέλασαν είχαμε χρησιμοποιούνταν λαμβάνουν. Για ότι συνάδελφος επί. Εργοστασίου βιβλίο μιας παράδειγμα ανταγωνιστής κανένας.', 'Αν όχι κάνε πρώτης εργασίας δούλευε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('181', '1309544067', '0507037201');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('181', '10086', '2018-06-14 00:00:00', '2018-06-21 00:00:00', 'Στις γραμμή κάνεις στο επιστρέφουν. Λοιπόν όταν ας πακέτων κάτι. Ύψος γραμμής βγήκε και.', 'Διαφήμιση αν πεδία παράδειγμα υποψήφιο μιας τις εντολές.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('182', '1710672160', '1109577348');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('182', '64853', '2024-03-23 00:00:00', '2024-04-28 00:00:00', 'Πάρεις συνέχεια άπειρα άρα ότι όχι της. Πρώτο μέχρι αποκλειστικούς εξοργιστικά κάτι άρα. Βουτήξουν πάντα πάντως για.', 'Μπορούσες κρατήσουν κι δωροδοκηθούν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('183', '1108564422', '2309635025');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('183', '53542', '2013-08-04 00:00:00', '2013-09-29 00:00:00', 'Αναφέρονται χρησιμοποιούσες χρειάζονται έτσι. Διευθυντές ειδικά σκεφτείς διάσημα κόψεις τρόπο ταξινομεί.', 'Συνάδελφος εδώ αναφορά έτσι μεταφραστής εργαζόμενοι στέλνοντάς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('184', '0504870342', '2803145534');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('184', '36593', '2017-04-27 00:00:00', '2017-05-02 00:00:00', 'Αντιλήφθηκαν έτσι ποια χώρου συγκεντρωμένοι. Χρησιμοποιούνταν το πηγαίου. Ο νέου να σταματάς πόρτες.', 'Πηγαίου την το μέχρι εξοργιστικά. Αν την έξι προκύπτουν τα διαπιστώνεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('185', '1309544067', '0906635373');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('185', '121220', '2019-04-30 00:00:00', '2019-05-05 00:00:00', 'Μια μετράει βιαστικά ανακλύψεις πάντως. Πρώτο νέα να πιο μάτσο.', 'Τι απαρατήρητο επεξεργασία εξακολουθεί μέχρι μη τον.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('186', '0704753686', '2309635025');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('186', '129126', '2023-03-18 00:00:00', '2023-04-22 00:00:00', 'Άρα που επί τέλειοι πρώτοι έρθει. Ποια νιρβάνα τον απαραίτητο. Στα ταξινομεί πλέον έξι ναι των επιχείριση όχι.', 'Έχω αρπάζεις θέλεις ένας ακούσει αθόρυβες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('187', '2701528412', '2901672412');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('187', '41727', '2026-10-09 00:00:00', '2026-11-04 00:00:00', 'Της πως προγραμματιστές ωραίο χαμηλός στο. Συγγραφείς μιας περιμένουν με. Στις την πλέον αρέσει παίξουν θέλεις μεταφραστής. Πως έξι τελειώσει λετπά πάρα εργασίας δυστυχής.', 'Χρησιμοποιώντας πρώτοι καταλάθος. Μα μας σαν γραμμές συγκεντρωμένοι οι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('188', '2503670784', '2002226263');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('188', '136037', '2004-12-29 00:00:00', '2005-01-06 00:00:00', 'Παίρνει εγώ ένα αρέσει. Στο ύψος προσθέσει έρθει επενδυτής πάρα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('189', '3004712447', '1711820259');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('189', '15817', '2007-11-18 00:00:00', '2008-01-05 00:00:00', 'Κανείς εφαρμογής στις σας. Εργαζόμενοι διακοπής περιβάλλον πες ένας παραδοτέου.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('190', '2504594248', '1909034370');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('190', '18018', '2000-01-29 00:00:00', '2000-02-05 00:00:00', 'Κώδικα μετρήσεις των ωραίο διορθώσει προγραμματιστές τις ειδικά. Αποθηκευτικού βουτήξουν δε εκείνου δε πετούν. Σπίτι υψηλότερη άρα υόρκη.', 'Περίπου περιβάλλοντος τεκμηριώνει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('191', '1108564422', '1512525167');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('191', '41373', '2008-08-31 00:00:00', '2008-10-10 00:00:00', 'Πες χρειάζονται χειρότερα εργοστασίου. Ανά τον ποια πως ως.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('192', '2312920992', '1408446826');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('192', '38247', '2000-04-04 00:00:00', '2000-05-02 00:00:00', 'Γνωρίζουμε μη τέλειοι βρίσκονται ζητήσεις. Απλό πλέον τι και ένας. Συνάδελφος ότι μάθε πρόσληψη. Εγώ χρονοδιαγράμματα συνεντεύξεις ποια έτσι ημέρα χρονοδιαγράμματα.', 'Τα εργασίας και έγραψες παίρνει. Διακοπή σχεδιαστής χρόνου συνέχεια τεσσαρών.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('193', '2011458949', '0207523564');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('193', '44192', '2011-04-23 00:00:00', '2011-05-31 00:00:00', 'Αποφάσισε λαμβάνουν υόρκη. Μέγιστη έξι όσο πάντως φίλος περιβάλλοντος ρουτίνα των. Πηγαίου ως απόλαυσε πολύ σημεία παράγοντες μέχρι.', 'Διαχειριστής την τις χρονοδιαγράμματα θυμάμαι προκύπτουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('194', '0202850965', '2810245025');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('194', '157014', '2011-05-02 00:00:00', '2011-06-16 00:00:00', 'Ένα έστειλε πολύ πάντως γραμμή. Βουτήξουν μεταγλωτιστής επεξεργασία που πετάξαμε κανόνα άπειρα.', 'Διάσημα πάντως μιας σας. Σε επί κάτι δύο σημαντικός.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('195', '0509904221', '0608151126');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('195', '78401', '2000-09-03 00:00:00', '2000-10-20 00:00:00', 'Τον βάζοντας επεξεργασία έξι ερώτηση μας δείξει. Έλεγχος όταν άπειρα πακέτων.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('196', '1110995980', '0808963976');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('196', '148406', '2018-10-07 00:00:00', '2018-10-30 00:00:00', 'Κοιτάζοντας και σας γραφικά κάνε πλέον κρατάει.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('197', '2011502344', '0708685120');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('197', '35228', '2025-01-01 00:00:00', '2025-03-01 00:00:00', 'Βγήκε κανένας πιο οι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('198', '0305769634', '0204044074');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('198', '153916', '2012-12-04 00:00:00', '2012-12-29 00:00:00', 'Ωραίο του διακόψουμε άλγεβρα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('199', '2808429905', '0605997909');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('199', '99017', '2002-05-06 00:00:00', '2002-06-02 00:00:00', 'Έτοιμος χρησιμοποιούσες ώρα. Αρπάζεις χρόνου επιδιορθώσεις καταλάθος προκαλείς διευθυντές νιρβάνα βουτήξουν.', 'Ξέχασε από βιβλίο απομόνωση. Τι το χαρτιού μιας μετρήσεις λαμβάνουν διαδίκτυο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('200', '1704959308', '1803761182');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('200', '23135', '2016-05-05 00:00:00', '2016-06-19 00:00:00', 'Έλεγχος μαγικά πήρε γιαυτό χάος εδώ. Μέχρι αλγόριθμου δημιουργείς. Κρατάει επιχείριση νέων τι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('201', '1108564422', '0709659298');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('201', '1894', '2005-03-09 00:00:00', '2005-04-27 00:00:00', 'Εσωτερικών ταξινομεί μάτσο επί ναι. Αναφορά απαράδεκτη διακόψουμε φίλος κλπ στα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('202', '2701528412', '2602192188');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('202', '39500', '2011-02-13 00:00:00', '2011-02-24 00:00:00', 'Απαραίτητο συγχρόνως απαραίτητο που ζητήσεις μεταφραστής. Τρόπο απίστευτα όχι στα. Αποθηκευτικού λες γεύματος γνωρίζουμε αποστηθίσει ειδικά.', 'Διαχειριστής εκδόσεις έτσι βουτήξουν διαπιστώνεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('203', '1110995980', '3003169109');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('203', '98108', '2011-11-30 00:00:00', '2011-12-05 00:00:00', 'Μεταγλωτίσει εκτελείται διακοπής περιμένουν πάντα αποθηκευτικού μη. Τεκμηριώνει πιο μη τη διορθώσει μάτσο.', 'Προκαλείς δύο πάντως. Ότι πως νέων ανά μηχανής διορθώσεις ότι προβληματική.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('204', '2011502344', '2109737700');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('204', '29917', '2016-08-03 00:00:00', '2016-09-24 00:00:00', 'Ποια όταν ένας. Να ποια πάντα αθόρυβες κρατήσουν. Πως όσο διακοπή μέχρι να τρέξει πακέτων τον. Κόλπα ατόμου προβληματική ημέρα.', 'Μου χειρότερα τύπου όχι δημιουργείς αποδείξεις πλέον.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('205', '2504594248', '3110857444');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('205', '19497', '2002-02-17 00:00:00', '2002-04-07 00:00:00', 'Εξαρτάται ως ίδιο της τεκμηριώνει παράδειγμα. Τεκμηριώνει ροή πήρε επεξεργασία ναι τον. Γνωστή έξι γιαυτό μπουν. Τύπου καλύτερο που πάρεις σχεδιαστής.', 'Παίξουν συγκεντρωμένοι στα διαφήμιση χρόνου που προσεκτικά ανεπιθύμητη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('206', '2009883975', '0502746763');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('206', '105685', '2009-06-24 00:00:00', '2009-06-30 00:00:00', 'Ρουτίνα περιμένουν προγραμματιστής τοπικές. Κανείς ότι από πάντως. Πετούν τα μετράει αγοράζοντας κειμένων χρόνου.', 'Τρόποι δεν κι ότι χρονοδιαγράμματος σημαντικός.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('207', '2202754126', '0906635373');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('207', '41628', '2016-06-29 00:00:00', '2016-08-05 00:00:00', 'Σε πήρε και γιαυτό ωραίο. Στο τον πάντως λοιπόν του εργαζόμενων χρησιμοποίησέ. Αναφορά μια εδώ πεδία μέχρι σας μου αλγόριθμου.', 'Εκτός διορθώσει απαρατήρητο μου. Κοιτάζοντας του συνηθίζουν αποθηκευτικού εδώ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('208', '1110429796', '0205213850');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('208', '55358', '2003-01-07 00:00:00', '2003-02-20 00:00:00', 'Γειτονιάς ιδιαίτερα μάθε αποφάσισε συνάδελφος. Που δημιουργια διαπιστώνεις δυστυχώς. Στέλνοντάς κάνεις ροή τον διολισθήσεις επιδιόρθωση σε προκύπτουν. Εξοργιστικά δοκιμάσεις προσεκτικά διακοπής.', 'Αποκλειστικούς χρησιμοποιούσες του σπίτι θυμάμαι ποια δε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('209', '0202850965', '1008634594');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('209', '498', '2006-02-08 00:00:00', '2006-03-26 00:00:00', 'Ως τους τη χάος κόψεις τις. Κώδικάς μια χάος έστελνε πάρα σαν πάντα μεταγλωτιστής. Απαράδεκτη εκείνου γραμμή.', 'Κρατήσουν εκτός μιας έστελνε. Εδώ νιρβάνα που εκτός εγώ ανά πολύ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('210', '2504923050', '0810951315');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('210', '132700', '2009-04-06 00:00:00', '2009-04-15 00:00:00', 'Όσο λετπά απομόνωση. Έχω εφαμοργής μετρήσεις πάντως και εταιρείες αποθηκευτικού. Των προσπαθούν διαδίκτυο δεν σας φράση. Βγήκε ένα περισσότερη υποψήφιο συνηθίζουν.', 'Κάτι ελέγχου διολισθήσεις. Υποψήφιο από δίνοντας κύκλο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('211', '2812759410', '2912542627');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('211', '90715', '2004-02-02 00:00:00', '2004-04-01 00:00:00', 'Βγήκε έτοιμος θυμάμαι εδώ στα παίρνει σε. Υψηλότερη δωροδοκηθούν κρατάει δίνοντας. Κύκλο εγώ όσο χώρου συγχρόνως κόψεις στέλνοντάς εργοστασίου.', 'Κι εργοστασίου ώρα πηγαίου θα όσο έξι ρουτίνα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('212', '2701528412', '1411108584');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('212', '46916', '2026-04-08 00:00:00', '2026-05-08 00:00:00', 'Παραγωγικής ποσοστό με γραμμές. Δούλευε λίγο μέχρι δουλεύει υπηρεσία.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('213', '2504594248', '2608706250');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('213', '2981', '2002-06-01 00:00:00', '2002-06-07 00:00:00', 'Περιβάλλοντος ξέχασε ροή μάθε αρχεία που. Συγχωνευτεί κι προσπαθήσεις των εδώ ημέρα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('214', '3004006308', '2803145534');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('214', '26069', '2019-12-17 00:00:00', '2020-01-22 00:00:00', 'Μέχρι μέγιστη συγχρόνως αποφάσισε. Προγραμματιστής πολύ βασανίζουν να. Κάνε διασφαλίζεται έτοιμος μη κανόνα συγχρόνως.', 'Λίγο γνωρίζουμε σε. Ανεπιθύμητη έστελνε συγγραφής διάβασε συγχρόνως χειρότερα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('215', '1303774169', '0708685120');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('215', '114244', '2016-12-04 00:00:00', '2017-01-28 00:00:00', 'Με μιας έλεγχος εδώ. Διορθώσεις πλέον σημεία νιρβάνα εγώ πιο εκθέσεις. Συγγραφής πάντως χρονοδιαγράμματα πολύ εκτελέσεις το.', 'Τις μαγικά πάντως μάθε. Ένα εκτελέσεις μαγικά εταιρείες ευκολότερο περιμένουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('216', '1710567296', '2909783680');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('216', '141793', '2020-01-13 00:00:00', '2020-02-22 00:00:00', 'Λιγότερο έγραψες επί διορθώσεις απαρατήρητο μάθε. Όχι προσπαθήσεις πιο και έξι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('217', '2901915784', '0511007549');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('217', '124679', '2001-12-04 00:00:00', '2001-12-13 00:00:00', 'Χρησιμοποιούνταν διαχειριστής δημιουργήσεις προκύπτουν κόψεις έλεγχος. Δύο συγκεντρωμένοι σταματάς δε εκθέσεις πάρα μην.', 'Ευκολότερο συνάδελφος εκτελέσεις εξακολουθεί αρχεία έξι ερώτηση αποθηκευτικού.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('218', '0202717529', '2204476056');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('218', '12184', '2019-10-17 00:00:00', '2019-11-06 00:00:00', 'Δε κι φίλος σας μια. Αρχεία προσπαθούν χρησιμοποίησέ ανακλύψεις προβληματική.', 'Αποδείξεις βρίσκονται υψηλότερη μέγιστη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('219', '1108613101', '2007023515');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '104853', '2011-08-16 00:00:00', '2011-10-11 00:00:00', 'Εκτός μια άπειρα ίδιο. Τι μάθε βγήκε δεν λέει εκτός. Βαθμό μέγιστη προκύπτουν και επιδιόρθωση. Θέμα μπουν επί ίδιο μετράει μην επιχείριση.', 'Κώδικάς βιβλίο καταλάθος με καλύτερο σαν σας μπορούσες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('220', '0609801977', '2911236182');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('220', '24858', '2003-02-13 00:00:00', '2003-03-10 00:00:00', 'Πρώτης ελέγχου εργασίας ίδιο δε ναι. Ζητήσεις στις ένας μην μερικούς. Πιο λες κι.', 'Προβληματική κειμένων τον ότι το. Φίλος έτσι παίρνουν δε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('221', '0202850965', '2810172600');
