INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('232', '147843', '2023-09-30 00:00:00', '2023-10-13 00:00:00', 'Σπίτι έτσι εγώ λίγο επιστρέφουν δεδομένων ποσοστό. Βιαστικά μας έστειλε προσθέσει σίγουρος λοιπόν. Ένας σχεδιαστής αθόρυβες πιο.', 'Τα μου πάντως χρησιμοποιούνταν ας. Με δυστυχώς μάτσο ανά σου μερικούς με.');
