INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('238', '2901915784', '3110857444');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('238', '145822', '2020-02-19 00:00:00', '2020-02-21 00:00:00', 'Των απόλαυσε βιαστικά κανόνα ήδη γέλασαν θέμα. Ίδιο συνηθίζουν περισσότερες επεξεργασία ρωτήσει. Του άρα ανακλύψεις δυστυχώς επί. Επί δυστυχής από διορθώσεις δύο μέχρι κάτι και.', 'Προσθέσει εκτός εκείνου δύο νέου βιαστικά.');
