INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('240', '1923', '2017-04-04 00:00:00', '2017-05-19 00:00:00', 'Λέει θα λοιπόν επί χάος ώρα. Μάθε τέλειοι αν απαρατήρητο. Στις ο ροή και.', 'Κόλπα εργαζόμενων παίρνουν πιο. Πάρεις προσεκτικά του πηγαίου επεξεργασία νέου.');
