INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('242', '38464', '2019-03-09 00:00:00', '2019-04-20 00:00:00', 'Πάντως ατόμου σημαντικός. Κώδικα τα απαράδεκτη διακοπή. Συνέχεια τη πακέτων εκθέσεις κλπ πρώτης εκείνου.', 'Τους μεταφραστής γειτονιάς να πλέον περιβάλλοντος. Εργοστασίου σαν πετάνε.');
