INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('244', '3004712447', '2606111574');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('244', '23326', '2010-06-23 00:00:00', '2010-08-21 00:00:00', 'Χρησιμοποιούνταν διακόψουμε πάντως να εκτελείται χρησιμοποιώντας δουλεύει. Ίδιο πάντα μα.', 'Ως καταλάθος ημέρα μπορούσες εδώ να.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('245', '0701585507', '2607536626');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('245', '104257', '2009-05-19 00:00:00', '2009-06-05 00:00:00', 'Αποστηθίσει αθόρυβες έλεγχος ποια. Κανένας εδώ παραδώσεις που μιας στο. Γραμμής θυμάμαι δουλεύει ερώτηση νέα. Ήδη απαραίτητο ξέχασε δημιουργια τι πάντα παίξουν.', 'Καλύτερο για πρώτης ιδιαίτερα μπορούσες δεν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('246', '2408650341', '0502746763');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('246', '30865', '2000-04-11 00:00:00', '2000-05-09 00:00:00', 'Ποια κόψεις εξοργιστικά αποθηκευτικού πηγαίου σπίτι έξι. Νέων μα εκείνου περιεχόμενα ελέγχου για. Δοκιμάσεις δυστυχής εκτελέσει τέλειοι εδώ διορθώσει ποσοστό. Μέγιστη πάντως απόλαυσε πετούν τι.', 'Χρονοδιαγράμματα ημέρα κοιτάζοντας μια τον. Χρονοδιαγράμματα μη άπειρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('247', '0305769634', '2008769961');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('247', '57759', '2011-01-04 00:00:00', '2011-01-20 00:00:00', 'Τύπους πάρεις προκαλείς επιδιόρθωση. Εικόνες στα κρατάει μια. Χρόνου νέο πιο νιρβάνα. Περιβάλλον νέο αναφορά προκύπτουν.', 'Προσοχή στο δεν τα πως τρόποι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('248', '2703870413', '0309126753');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('248', '61665', '2026-04-08 00:00:00', '2026-05-13 00:00:00', 'Ξέχασε άρα πετάξαμε αποδείξεις απόλαυσε εργοστασίου. Πόρτες χαρακτηριστικών διασφαλίζεται.', 'Χρησιμοποίησέ ποια πετάξαμε προκύπτουν άρα ανώδυνη.');
