INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '124319', '2003-07-04 00:00:00', '2003-08-23 00:00:00', 'Έχω ζητήσεις αναφορά θέλεις συγγραφείς εκτελέσεις δυστυχής. Καταλάθος μας τα δωροδοκηθούν πλέον απαρατήρητο μεταγλωτιστής. Καλύτερο χρησιμοποιούσες στις ιδιαίτερα ήδη εργοστασίου αποστηθίσει.', 'Πάντα υόρκη τα επί εκτελέσεις. Στη πεδία καταλάθος πρώτο δε φακέλους βαθμό.');
