INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('259', '2504594248', '0206102410');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('259', '4171', '2017-07-13 00:00:00', '2017-07-31 00:00:00', 'Ανώδυνη μηχανής ωραίο δεν μας τύπους εσωτερικών. Αθόρυβες γραμμής σημαντικός αρπάζεις πάντα μάλλον.', 'Άρα επιδιορθώσεις μπορούσες βρίσκονται προσπαθούν. Στήλες θα αρχεία δύο.');
