INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('262', '118891', '2000-04-21 00:00:00', '2000-05-25 00:00:00', 'Ο χαρακτηριστικό προϊόντα υποψήφιο αντιλήφθηκαν περισσότερη πρώτοι της.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('263', '0412557508', '2510866176');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('263', '139953', '2016-01-03 00:00:00', '2016-03-02 00:00:00', 'Κόλπα εγώ παραδοτέου εντολές με τη μια ρουτίνα. Ώρα σε παραγωγικής θα διορθώσεις φράση λες. Στο χρησιμοποιώντας εκτός διευθυντές εξακολουθεί βιαστικά όχι.', 'Πάντα τι προβληματική πολύ σου. Δυστυχώς μεταγλωτίσει το μη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('264', '3010528248', '2612825673');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('264', '87329', '2017-10-24 00:00:00', '2017-11-16 00:00:00', 'Σημεία ειδικά εκτός γιαυτό.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('265', '3010528248', '0902978915');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('265', '112656', '2013-06-06 00:00:00', '2013-06-19 00:00:00', 'Εγώ κανένας συνεντεύξεις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('266', '2009883975', '2406132072');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('266', '48701', '2025-06-22 00:00:00', '2025-07-20 00:00:00', 'Στις έξι ερωτήσεις ωραίο κώδικα ως. Δουλεύει προγραμματιστής ότι μου ανακλύψεις άρα. Δύο δοκιμάσεις κάτι δημιουργείς.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('267', '3101684544', '2208147233');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('267', '40376', '2004-01-25 00:00:00', '2004-02-25 00:00:00', 'Κάνε εργάστηκε δοκιμάσεις ποια προσεκτικά μεταγλωτιστής. Πιο χάος εργαλείων αναγκάζονται. Πλέον εξακολουθεί κλπ οι δωροδοκηθούν που τον.', 'Πάντα έχω κάνεις μερικούς ανά δίνοντας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('268', '2011458949', '3103676568');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('268', '103000', '2018-04-13 00:00:00', '2018-05-04 00:00:00', 'Τεκμηριώνει κι θυμάμαι για δύο. Παίρνουν ανεπιθύμητη συγκεντρωμένοι στο παραδοτέου από για να. Ίδιο πολύ του παραγωγικής κάνε κόψεις επεξεργασία.', 'Ας με αν. Έξι γειτονιάς νέου δύο. Με νέου γνωρίζουμε απαρατήρητο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('269', '0504870342', '0810951315');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('269', '161004', '2020-04-21 00:00:00', '2020-05-31 00:00:00', 'Συνεντεύξεις ειδικά βασανίζουν όσο ρωτήσει. Διοικητικό δεδομένων βιβλίο ότι έξι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('270', '3011473425', '2611668702');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('270', '154058', '2019-11-29 00:00:00', '2020-01-14 00:00:00', 'Της ο και μηχανής περιεχόμενα σαν τη. Επενδυτής πρώτης λιγότερο χαμηλός. Κάτι ποια νέα χαρακτηριστικό όχι χρησιμοποίησέ.', 'Περιεχόμενα άρα ώρα ύψος επί απίστευτα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('271', '2010417306', '0709659298');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '154652', '2012-07-29 00:00:00', '2012-09-05 00:00:00', 'Σαν καλύτερο για πρώτοι. Πάντα έτσι προβληματική μην υπηρεσία γεγονός δεδομένων.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('272', '1207891405', '1606589624');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('272', '123420', '2006-04-05 00:00:00', '2006-05-25 00:00:00', 'Εδώ μετρήσεις καταλάθος. Εργαλείων σωστά εκτός.', 'Χώρου κανείς πηγαίου δωροδοκηθούν στραβά εκτός βουτήξουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('273', '3010528248', '2608706250');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('273', '156818', '2015-08-10 00:00:00', '2015-08-14 00:00:00', 'Συγκεντρωμένοι δύο ευκολότερο μετρήσεις άλγεβρα παίρνουν ανεπιθύμητη. Γραμμής κανόνα εδώ προσπαθούν. Αρχεία που παράδειγμα εκδόσεις θα.', 'Μεταγλωτιστής υόρκη περίπου στο πάντα. Μας δημιουργια αρέσει από προϊόντα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('274', '2708902048', '0206102410');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('274', '123286', '2003-10-29 00:00:00', '2003-11-05 00:00:00', 'Κύκλο τα των μάτσο παραπάνω παραδοτέου άλγεβρα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('275', '3003792611', '1803831080');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('275', '106524', '2004-05-29 00:00:00', '2004-07-23 00:00:00', 'Πολύ και τρόπο αγοράζοντας από κόλπα ανά ότι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('276', '1603973073', '2103241696');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('276', '83973', '2000-02-03 00:00:00', '2000-03-23 00:00:00', 'Άπειρα ρουτίνα απόλαυσε σημεία.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('277', '1208533496', '2207135019');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('277', '150363', '2005-12-09 00:00:00', '2006-01-12 00:00:00', 'Από πως μπουν εγώ επιδιορθώσεις ένα. Μεταγλωτιστής ήδη αναφέρονται μη διολισθήσεις μέσης των.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('278', '2808429905', '3103676568');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('278', '32470', '2003-12-09 00:00:00', '2004-01-01 00:00:00', 'Τεκμηριώνει πάντα ερωτήσεις που συνηθίζουν. Τον αυτήν πάντα ευκολότερο φαινόμενο ζητήσεις. Παίρνει συγκεντρωμένοι να στα. Συγγραφής τέλειοι επιστρέφουν χαμηλός όσο απαραίτητο πολύ.', 'Δημιουργια μα μέχρι φράση. Σημεία εδώ με νέων. Τι μιας με γραμμές.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('279', '2812759410', '1710114805');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('279', '126329', '2025-06-09 00:00:00', '2025-07-11 00:00:00', 'Τη προσλάμβανες μιας μα αν. Κανείς ένα μέχρι ώρα τα αναφέρονται. Δίνοντας από έτσι ανώδυνη στο γειτονιάς.', 'Κάτι ελέγχου αρπάζεις δίνοντας πες σκεφτείς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('280', '1303774169', '0808697162');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('280', '38276', '2016-07-12 00:00:00', '2016-09-03 00:00:00', 'Εξαρτάται διακοπή σχεδιαστής του τι πρώτοι ελέγχου φακέλους. Στέλνοντάς γνωρίζουμε κειμένων ώρα μάλλον χρονοδιαγράμματος εκτός τύπου. Του πλέον διορθώσεις στη.', 'Βαθμό κανείς ευκολότερο. Στο γραμμής πρώτοι στα επιχείριση.');
